export interface UserProfile {
  name: string;
  relationship: string;
  interests: string[];
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export enum ConnectionStatus {
  DISCONNECTED = 'DISCONNECTED',
  CONNECTING = 'CONNECTING',
  CONNECTED = 'CONNECTED',
  ERROR = 'ERROR'
}

export function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function encode(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function createPcmBlob(data: Float32Array): { data: string; mimeType: string } {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = Math.max(-1, Math.min(1, data[i])) * 32768;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

import React, { useEffect, useRef } from 'react';

interface WaveformProps {
  isActive: boolean;
  color: string;
  amplitude?: number;
}

const Waveform: React.FC<WaveformProps> = ({ isActive, color, amplitude = 0 }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationRef = useRef<number>();

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let offset = 0;
    const draw = () => {
      const { width, height } = canvas;
      ctx.clearRect(0, 0, width, height);

      if (isActive) {
        ctx.beginPath();
        ctx.strokeStyle = color;
        ctx.lineWidth = 3;
        ctx.lineCap = 'round';

        const midY = height / 2;
        const segments = 40;
        const segmentWidth = width / segments;

        ctx.moveTo(0, midY);

        for (let i = 0; i <= segments; i++) {
          const x = i * segmentWidth;
          const variance = isActive ? amplitude * 50 : 2;
          const y = midY + Math.sin(i * 0.5 + offset) * variance;
          ctx.lineTo(x, y);
        }

        ctx.stroke();
        offset += 0.15;
      } else {
        // Flat line when inactive
        ctx.beginPath();
        ctx.strokeStyle = '#334155';
        ctx.lineWidth = 2;
        ctx.moveTo(0, height / 2);
        ctx.lineTo(width, height / 2);
        ctx.stroke();
      }

      animationRef.current = requestAnimationFrame(draw);
    };

    draw();
    return () => {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [isActive, color, amplitude]);

  return (
    <canvas 
      ref={canvasRef} 
      width={300} 
      height={100} 
      className="w-full h-24 rounded-lg"
    />
  );
};

export default Waveform;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { decode, decodeAudioData, createPcmBlob } from './audioUtils';
import { UserProfile, ChatMessage, ConnectionStatus } from './types';
import Waveform from './components/Waveform';

// Audio Constants
const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

const App: React.FC = () => {
  // --- State ---
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('social_gemini_profile');
    return saved ? JSON.parse(saved) : null;
  });
  const [isProfileModalOpen, setIsProfileModalOpen] = useState(!userProfile);
  const [transcription, setTranscription] = useState<string>('');
  const [rmsInput, setRmsInput] = useState(0);
  const [rmsOutput, setRmsOutput] = useState(0);

  // --- Refs ---
  const inputAudioCtxRef = useRef<AudioContext | null>(null);
  const outputAudioCtxRef = useRef<AudioContext | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      disconnect();
    };
  }, []);

  // --- Audio Engine ---
  const getAudioContexts = () => {
    if (!inputAudioCtxRef.current) {
      inputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: INPUT_SAMPLE_RATE });
    }
    if (!outputAudioCtxRef.current) {
      outputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: OUTPUT_SAMPLE_RATE });
    }
    return { input: inputAudioCtxRef.current, output: outputAudioCtxRef.current };
  };

  const stopAllAudio = useCallback(() => {
    sourcesRef.current.forEach(source => {
      try { source.stop(); } catch (e) {}
    });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
    setRmsOutput(0);
    setRmsInput(0);

    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
  }, []);

  // --- Session Management ---
  const connect = async () => {
    if (!userProfile) {
      setIsProfileModalOpen(true);
      return;
    }

    try {
      setStatus(ConnectionStatus.CONNECTING);
      const { input, output } = getAudioContexts();

      // Resume contexts for browser security
      await input.resume();
      await output.resume();

      // Create new instance per connection to ensure fresh API keys
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const systemInstruction = `
        You are a warm, socially intelligent AI companion. 
        User's Name: ${userProfile.name}. 
        Relationship with user: ${userProfile.relationship}.
        User's Interests: ${userProfile.interests.join(', ')}.

        Personality & Behavior:
        - Treat this as a casual phone call with a close friend.
        - Don't just answer questions; share observations and "thoughts" to keep the flow.
        - Avoid formal AI language ("I am an AI", "How can I help you today?").
        - Reference the user's interests naturally during conversation.
        - Keep responses concise but engaging. 
        - Never end with a generic prompt like "What's next?". Just let the silence or a natural thought lead.
      `;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }, // Warm, friendly voice
          },
          systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setStatus(ConnectionStatus.CONNECTED);
            const source = input.createMediaStreamSource(stream);
            const processor = input.createScriptProcessor(4096, 1, 1);
            processorRef.current = processor;

            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);

              // Input volume meter
              let sum = 0;
              for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
              setRmsInput(Math.sqrt(sum / inputData.length));

              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(processor);
            processor.connect(input.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle Transcriptions for visual feedback
            if (message.serverContent?.inputTranscription) {
              setTranscription(prev => (prev.length > 100 ? '...' : prev) + ' ' + message.serverContent?.inputTranscription?.text);
            }
            if (message.serverContent?.outputTranscription) {
              setTranscription(prev => (prev.length > 100 ? '...' : prev) + ' ' + message.serverContent?.outputTranscription?.text);
            }
            if (message.serverContent?.turnComplete) {
              setTranscription('');
            }

            // Handle Audio Data
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
              const audioBuffer = await decodeAudioData(decode(base64Audio), output, OUTPUT_SAMPLE_RATE, 1);
              const source = output.createBufferSource();
              source.buffer = audioBuffer;

              // Visualization: Sample the output audio for volume
              const channelData = audioBuffer.getChannelData(0);
              let sum = 0;
              for(let i=0; i < channelData.length; i+=100) sum += channelData[i] * channelData[i];
              setRmsOutput(Math.sqrt(sum / (channelData.length/100)));

              source.connect(output.destination);

              // Scheduling for smooth playback
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, output.currentTime);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;

              sourcesRef.current.add(source);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setRmsOutput(0);
              };
            }

            // Handle Interruptions
            if (message.serverContent?.interrupted) {
              stopAllAudio();
              // Re-enable contexts for next turn
              input.resume();
              output.resume();
            }
          },
          onerror: (e) => {
            console.error('Session error:', e);
            setStatus(ConnectionStatus.ERROR);
            stopAllAudio();
          },
          onclose: () => {
            setStatus(ConnectionStatus.DISCONNECTED);
            stopAllAudio();
          },
        },
      });

      sessionPromiseRef.current = sessionPromise;
    } catch (err) {
      console.error('Connection failed:', err);
      setStatus(ConnectionStatus.ERROR);
    }
  };

  const disconnect = () => {
    if (sessionPromiseRef.current) {
      sessionPromiseRef.current.then(session => {
        try { session.close(); } catch (e) {}
      });
    }
    stopAllAudio();
    setStatus(ConnectionStatus.DISCONNECTED);
  };

  const saveProfile = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      relationship: formData.get('relationship') as string,
      interests: (formData.get('interests') as string).split(',').map(s => s.trim()).filter(Boolean),
    };
    setUserProfile(profile);
    localStorage.setItem('social_gemini_profile', JSON.stringify(profile));
    setIsProfileModalOpen(false);
  };

  return (
    <div className="flex flex-col h-screen bg-slate-950 text-slate-100 p-4 md:p-10 font-sans">
      {/* App Header */}
      <header className="flex justify-between items-center z-10">
        <div className="flex flex-col">
          <h1 className="text-2xl font-black tracking-tight bg-gradient-to-r from-cyan-400 to-indigo-500 bg-clip-text text-transparent">
            Social Gemini
          </h1>
          <div className="flex items-center space-x-2 mt-1">
            <span className={`w-2 h-2 rounded-full ${status === ConnectionStatus.CONNECTED ? 'bg-green-500 animate-pulse' : 'bg-slate-700'}`}></span>
            <span className="text-[10px] uppercase tracking-widest font-bold text-slate-500">
              {status.replace('_', ' ')}
            </span>
          </div>
        </div>

        <button 
          onClick={() => setIsProfileModalOpen(true)}
          className="w-10 h-10 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center hover:bg-slate-800 transition-all active:scale-90 shadow-xl"
        >
          <i className="fas fa-id-card text-slate-400 text-sm"></i>
        </button>
      </header>

      {/* Main Experience */}
      <main className="flex-1 flex flex-col items-center justify-center relative">
        {/* Glow Background Effect */}
        <div className={`absolute w-64 h-64 bg-cyan-500/10 rounded-full blur-[100px] transition-opacity duration-1000 ${status === ConnectionStatus.CONNECTED ? 'opacity-100' : 'opacity-0'}`}></div>

        {/* The "Orb" - Dynamic representation of the AI */}
        <div className="relative mb-12">
          <div className={`absolute -inset-8 bg-gradient-to-tr from-cyan-500 to-indigo-600 rounded-full blur-2xl opacity-20 transition-all duration-1000 ${status === ConnectionStatus.CONNECTED ? 'scale-125 opacity-40' : 'scale-75 opacity-0'}`}></div>
          <div className={`w-48 h-48 rounded-full flex items-center justify-center border-2 shadow-2xl transition-all duration-700 ${status === ConnectionStatus.CONNECTED ? 'border-cyan-400/50 bg-slate-900/50 scale-105' : 'border-slate-800 bg-slate-950'}`}>
            {status === ConnectionStatus.CONNECTING ? (
              <i className="fas fa-atom fa-spin text-4xl text-cyan-400"></i>
            ) : status === ConnectionStatus.CONNECTED ? (
              <div className="flex space-x-1 items-end h-12">
                {[...Array(5)].map((_, i) => (
                  <div 
                    key={i} 
                    className="w-2 bg-cyan-400 rounded-full transition-all duration-100"
                    style={{ height: `${20 + (rmsOutput * 300 * Math.random())}%` }}
                  />
                ))}
              </div>
            ) : (
              <i className="fas fa-microphone-slash text-slate-700 text-3xl"></i>
            )}
          </div>
        </div>

        {/* Visual Feedback and Transcription */}
        <div className="w-full max-w-sm space-y-6">
          <Waveform 
            isActive={status === ConnectionStatus.CONNECTED} 
            color="#22d3ee" 
            amplitude={Math.max(rmsInput, rmsOutput)} 
          />

          <div className="bg-slate-900/40 backdrop-blur-md rounded-3xl p-6 min-h-[140px] flex items-center justify-center border border-white/5 shadow-inner">
            <p className="text-slate-300 text-center leading-relaxed text-lg font-medium italic opacity-80">
              {transcription || (status === ConnectionStatus.CONNECTED ? "Go ahead, I'm listening..." : "Tap below to start your companion session.")}
            </p>
          </div>
        </div>
      </main>

      {/* Control Bar */}
      <footer className="z-10 flex justify-center pb-8 pt-4">
        {status === ConnectionStatus.CONNECTED ? (
          <button 
            onClick={disconnect}
            className="group flex items-center space-x-4 px-10 py-5 bg-slate-900 border border-slate-800 text-slate-300 rounded-full font-bold shadow-2xl hover:bg-red-500/10 hover:border-red-500/30 hover:text-red-400 transition-all active:scale-95"
          >
            <div className="w-8 h-8 rounded-full bg-red-500/20 flex items-center justify-center group-hover:bg-red-500 group-hover:text-white transition-colors">
              <i className="fas fa-phone-slash text-sm"></i>
            </div>
            <span>End Call</span>
          </button>
        ) : (
          <button 
            onClick={connect}
            disabled={status === ConnectionStatus.CONNECTING}
            className="group flex items-center space-x-4 px-12 py-5 bg-gradient-to-br from-cyan-500 to-indigo-600 text-white rounded-full font-bold shadow-2xl shadow-cyan-500/20 hover:shadow-cyan-500/40 transition-all active:scale-95 disabled:opacity-50"
          >
            <div className="w-8 h-8 rounded-full bg-white/20 flex items-center justify-center group-hover:scale-110 transition-transform">
              <i className={`fas ${status === ConnectionStatus.CONNECTING ? 'fa-circle-notch fa-spin' : 'fa-phone'} text-sm`}></i>
            </div>
            <span className="text-lg">{status === ConnectionStatus.CONNECTING ? 'Connecting...' : 'Call Companion'}</span>
          </button>
        )}
      </footer>

      {/* Persistent User Profile Modal */}
      {isProfileModalOpen && (
        <div className="fixed inset-0 bg-slate-950/90 backdrop-blur-xl z-[100] flex items-center justify-center p-4">
          <div className="bg-slate-900 border border-slate-800 rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in fade-in zoom-in duration-300">
            <div className="mb-8">
              <h2 className="text-2xl font-black mb-2">Memory Setup</h2>
              <p className="text-slate-400 text-sm">Tell your AI companion a bit about yourself so conversations flow naturally.</p>
            </div>

            <form onSubmit={saveProfile} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Your Name</label>
                <input 
                  name="name" 
                  required 
                  defaultValue={userProfile?.name}
                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 focus:outline-none focus:ring-2 focus:ring-cyan-500/50 transition-all placeholder:text-slate-700"
                  placeholder="How should I address you?"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">The Vibe / Relationship</label>
                <input 
                  name="relationship" 
                  required 
                  defaultValue={userProfile?.relationship || "Best Friend"}
                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 focus:outline-none focus:ring-2 focus:ring-cyan-500/50 transition-all placeholder:text-slate-700"
                  placeholder="e.g. Sarcastic Buddy, Intellectual Peer"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Your Interests</label>
                <textarea 
                  name="interests" 
                  defaultValue={userProfile?.interests.join(', ')}
                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-5 py-4 focus:outline-none focus:ring-2 focus:ring-cyan-500/50 transition-all h-28 placeholder:text-slate-700 resize-none"
                  placeholder="Cooking, tech, philosophy, sci-fi movies..."
                />
              </div>
              <div className="flex flex-col space-y-3 pt-2">
                <button 
                  type="submit"
                  className="w-full py-5 bg-gradient-to-r from-cyan-400 to-indigo-500 text-slate-950 font-black text-lg rounded-2xl transition-all shadow-xl shadow-cyan-500/10 hover:shadow-cyan-500/20 active:scale-[0.98]"
                >
                  Confirm Memory
                </button>
                {userProfile && (
                  <button 
                    type="button"
                    onClick={() => setIsProfileModalOpen(false)}
                    className="w-full py-2 text-slate-500 text-xs font-bold uppercase tracking-widest"
                  >
                    Close
                  </button>
                )}
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { decode, decodeAudioData, createPcmBlob } from './audioUtils';
import { UserProfile, ChatMessage, ConnectionStatus } from './types';
import Waveform from './components/Waveform';

const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

const App: React.FC = () => {
  // --- State ---
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('social_gemini_profile');
    return saved ? JSON.parse(saved) : null;
  });

  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [history, setHistory] = useState<ChatMessage[]>(() => {
    const saved = localStorage.getItem('social_gemini_history');
    return saved ? JSON.parse(saved) : [];
  });
  const [transcription, setTranscription] = useState<string>('');
  const [rmsInput, setRmsInput] = useState(0);
  const [rmsOutput, setRmsOutput] = useState(0);

  // Buffer for building full messages
  const currentTurnRef = useRef<{ user: string; model: string }>({ user: '', model: '' });

  // --- Refs ---
  const inputAudioCtxRef = useRef<AudioContext | null>(null);
  const outputAudioCtxRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  // Sync history to localStorage
  useEffect(() => {
    localStorage.setItem('social_gemini_history', JSON.stringify(history));
  }, [history]);

  // Check for API Key on load
  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio?.hasSelectedApiKey) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(selected);
      } else {
        // If not in aistudio environment, we assume process.env.API_KEY is handled
        setHasApiKey(!!process.env.API_KEY);
      }
    };
    checkKey();
    if (!userProfile) setIsProfileModalOpen(true);
  }, []);

  const handleOpenSelectKey = async () => {
    if (window.aistudio?.openSelectKey) {
      await window.aistudio.openSelectKey();
      // Per instructions, assume success to mitigate race conditions
      setHasApiKey(true);
      setErrorMessage(null);
    }
  };

  const getAudioContexts = async () => {
    if (!inputAudioCtxRef.current) {
      inputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: INPUT_SAMPLE_RATE });
    }
    if (!outputAudioCtxRef.current) {
      outputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: OUTPUT_SAMPLE_RATE });
    }

    // Ensure they are running (crucial for mobile/Android)
    if (inputAudioCtxRef.current.state === 'suspended') await inputAudioCtxRef.current.resume();
    if (outputAudioCtxRef.current.state === 'suspended') await outputAudioCtxRef.current.resume();

    return { input: inputAudioCtxRef.current, output: outputAudioCtxRef.current };
  };

  const stopAllAudio = useCallback(() => {
    sourcesRef.current.forEach(source => {
      try { source.stop(); } catch (e) {}
    });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
    setRmsOutput(0);
    setRmsInput(0);

    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    sessionRef.current = null;
  }, []);

  const connect = async () => {
    if (status === ConnectionStatus.CONNECTING) return;

    if (!hasApiKey && window.aistudio) {
      handleOpenSelectKey();
      return;
    }

    if (!userProfile) {
      setIsProfileModalOpen(true);
      return;
    }

    try {
      setErrorMessage(null);
      setStatus(ConnectionStatus.CONNECTING);

      const { input, output } = await getAudioContexts();

      // Create a fresh instance for every connection attempt as requested
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const systemInstruction = `
        You are a socially intelligent, warm AI companion. 
        User's Name: ${userProfile.name}. 
        Relationship: ${userProfile.relationship}.
        Interests: ${userProfile.interests.join(', ')}.

        Behavior Guidelines:
        - This is a casual, reciprocal social conversation.
        - Don't just answer questions; share thoughts, ask about the user, and be a good listener.
        - Keep responses concise so the interaction feels like a real-time call.
        - Avoid ending with generic prompts like "What's next?". Let the conversation breathe.
        - Reference past interests naturally.
      `;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
          },
          systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setStatus(ConnectionStatus.CONNECTED);
            const source = input.createMediaStreamSource(stream);
            const processor = input.createScriptProcessor(4096, 1, 1);
            processorRef.current = processor;

            processor.onaudioprocess = (e) => {
              if (status !== ConnectionStatus.CONNECTED) return;

              const inputData = e.inputBuffer.getChannelData(0);

              let sum = 0;
              for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
              setRmsInput(Math.sqrt(sum / inputData.length));

              const pcmBlob = createPcmBlob(inputData);
              // Send input only if session is ready
              sessionPromise.then(session => {
                if (session && status === ConnectionStatus.CONNECTED) {
                  session.sendRealtimeInput({ media: pcmBlob });
                }
              });
            };

            source.connect(processor);
            processor.connect(input.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              setTranscription(prev => (prev + ' ' + text).trim());
              currentTurnRef.current.user += text;
            }
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              setTranscription(prev => (prev + ' ' + text).trim());
              currentTurnRef.current.model += text;
            }
            if (message.serverContent?.turnComplete) {
              const userText = currentTurnRef.current.user.trim();
              const modelText = currentTurnRef.current.model.trim();

              if (userText || modelText) {
                setHistory(prev => [
                  ...prev,
                  { role: 'user', text: userText || '(Speech input)', timestamp: Date.now() },
                  { role: 'model', text: modelText || '(Speech output)', timestamp: Date.now() }
                ].slice(-50));
              }

              currentTurnRef.current = { user: '', model: '' };
              setTranscription('');
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
              const audioBuffer = await decodeAudioData(decode(base64Audio), output, OUTPUT_SAMPLE_RATE, 1);
              const source = output.createBufferSource();
              source.buffer = audioBuffer;

              const channelData = audioBuffer.getChannelData(0);
              let sum = 0;
              const step = Math.max(1, Math.floor(channelData.length / 100));
              for(let i=0; i < channelData.length; i+=step) sum += channelData[i] * channelData[i];
              setRmsOutput(Math.sqrt(sum / (channelData.length/step)));

              source.connect(output.destination);
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, output.currentTime);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;

              sourcesRef.current.add(source);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setRmsOutput(0);
              };
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e: any) => {
            console.error('Session error detail:', e);
            const msg = (e?.message || e?.toString() || '').toLowerCase();

            if (msg.includes('requested entity was not found') || msg.includes('404')) {
              setErrorMessage("Model or Project not found. Resetting API key...");
              setHasApiKey(false);
              // Prompt to re-select
              if (window.aistudio?.openSelectKey) window.aistudio.openSelectKey();
            } else if (msg.includes('network error') || msg.includes('failed to fetch')) {
              setErrorMessage("Network error. Please check your connection.");
            } else {
              setErrorMessage("Disconnected. Tap to try again.");
            }

            setStatus(ConnectionStatus.ERROR);
            stopAllAudio();
          },
          onclose: () => {
            if (status !== ConnectionStatus.ERROR) {
              setStatus(ConnectionStatus.DISCONNECTED);
            }
            stopAllAudio();
          },
        },
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      console.error('Connection failed:', err);
      setStatus(ConnectionStatus.ERROR);
      setErrorMessage(err?.message || "Connection failed. Check your API key and network.");
      stopAllAudio();
    }
  };

  const disconnect = () => {
    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch (e) {}
    }
    stopAllAudio();
    setStatus(ConnectionStatus.DISCONNECTED);
  };

  const saveProfile = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      relationship: formData.get('relationship') as string,
      interests: (formData.get('interests') as string).split(',').map(s => s.trim()).filter(Boolean),
    };
    setUserProfile(profile);
    localStorage.setItem('social_gemini_profile', JSON.stringify(profile));
    setIsProfileModalOpen(false);
  };

  return (
    <div className="flex flex-col h-screen bg-slate-950 text-slate-100 p-4 md:p-10 font-sans select-none overflow-hidden">
      {/* Header */}
      <header className="flex justify-between items-center shrink-0 z-10">
        <div>
          <h1 className="text-xl font-black tracking-tighter bg-gradient-to-r from-cyan-400 to-blue-500 bg-clip-text text-transparent">
            Social Gemini
          </h1>
          <div className="flex items-center space-x-2">
            <span className={`w-1.5 h-1.5 rounded-full ${status === ConnectionStatus.CONNECTED ? 'bg-cyan-400 animate-pulse' : status === ConnectionStatus.ERROR ? 'bg-red-500' : 'bg-slate-700'}`}></span>
            <span className="text-[9px] uppercase tracking-widest font-bold text-slate-500">
              {status}
            </span>
          </div>
        </div>

        <div className="flex space-x-2">
          <button 
            onClick={() => setIsHistoryOpen(true)}
            className="w-10 h-10 rounded-xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-400 hover:text-cyan-400 active:scale-90 transition-all"
            aria-label="History"
          >
            <i className="fas fa-history text-sm"></i>
          </button>
          <button 
            onClick={() => setIsProfileModalOpen(true)}
            className="w-10 h-10 rounded-xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-400 hover:text-cyan-400 active:scale-90 transition-all"
            aria-label="Profile"
          >
            <i className="fas fa-user-circle text-sm"></i>
          </button>
        </div>
      </header>

      {/* Main Experience */}
      <main className="flex-1 flex flex-col items-center justify-center space-y-8 relative">
        {/* Ambient Glow */}
        <div className={`absolute w-72 h-72 bg-cyan-500/10 rounded-full blur-[100px] transition-opacity duration-1000 ${status === ConnectionStatus.CONNECTED ? 'opacity-100' : 'opacity-0'}`}></div>

        <div className="relative group">
          {/* Pulsing Ring */}
          <div className={`absolute -inset-10 bg-cyan-500/20 rounded-full blur-3xl transition-all duration-700 ${status === ConnectionStatus.CONNECTED ? 'scale-110 opacity-60' : 'scale-0 opacity-0'}`}></div>

          <button 
            onClick={status === ConnectionStatus.CONNECTED ? disconnect : connect}
            disabled={status === ConnectionStatus.CONNECTING}
            className={`relative w-40 h-40 rounded-full flex items-center justify-center border-2 transition-all duration-500 shadow-2xl ${
              status === ConnectionStatus.CONNECTED 
                ? 'border-cyan-400/50 bg-slate-900/60 scale-105 shadow-cyan-500/20' 
                : status === ConnectionStatus.ERROR
                ? 'border-red-500/50 bg-slate-950 scale-100'
                : 'border-slate-800 bg-slate-950 scale-100'
            }`}
          >
            {status === ConnectionStatus.CONNECTING ? (
              <i className="fas fa-circle-notch fa-spin text-3xl text-cyan-400"></i>
            ) : status === ConnectionStatus.CONNECTED ? (
              <div className="flex items-end space-x-1.5 h-10">
                {[...Array(5)].map((_, i) => (
                  <div 
                    key={i} 
                    className="w-2 bg-cyan-400 rounded-full transition-all duration-75"
                    style={{ height: `${20 + (rmsOutput * 500 * (0.5 + Math.random()))}%` }}
                  />
                ))}
              </div>
            ) : status === ConnectionStatus.ERROR ? (
              <i className="fas fa-exclamation-triangle text-red-500 text-3xl"></i>
            ) : (
              <i className="fas fa-microphone text-slate-600 group-hover:text-cyan-400 text-3xl transition-colors"></i>
            )}
          </button>
        </div>

        <div className="w-full max-w-sm space-y-6 px-6 text-center">
          <Waveform isActive={status === ConnectionStatus.CONNECTED} color="#22d3ee" amplitude={Math.max(rmsInput, rmsOutput)} />

          <div className="min-h-[60px] flex items-center justify-center">
            {errorMessage ? (
              <p className="text-red-400 text-xs font-semibold px-4 py-2 bg-red-500/10 rounded-full border border-red-500/20">
                {errorMessage}
              </p>
            ) : (
              <p className="text-slate-400 text-sm font-medium italic animate-in fade-in slide-in-from-bottom-2 duration-500 line-clamp-3 leading-relaxed">
                {transcription || (status === ConnectionStatus.CONNECTED ? "I'm listening..." : "Tap the mic to start a relaxed conversation") }
              </p>
            )}
          </div>
        </div>
      </main>

      {/* Footer Controls */}
      <footer className="shrink-0 flex justify-center pb-8">
        {status === ConnectionStatus.CONNECTED ? (
          <button 
            onClick={disconnect}
            className="flex items-center space-x-3 px-10 py-4 bg-slate-900 border border-slate-800 text-red-400 rounded-3xl font-bold shadow-xl active:scale-95 transition-all hover:bg-slate-800"
          >
            <i className="fas fa-phone-slash"></i>
            <span>Hang up</span>
          </button>
        ) : (
          <button 
            onClick={connect}
            disabled={status === ConnectionStatus.CONNECTING}
            className="flex items-center space-x-3 px-10 py-4 bg-gradient-to-r from-cyan-600 to-blue-600 text-white rounded-3xl font-bold shadow-xl active:scale-95 transition-all disabled:opacity-50 disabled:grayscale"
          >
            <i className="fas fa-comment-dots"></i>
            <span>{status === ConnectionStatus.CONNECTING ? "Connecting..." : "Start Chat"}</span>
          </button>
        )}
      </footer>

      {/* Profile Modal */}
      {isProfileModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-950/90 backdrop-blur-sm">
          <div className="w-full max-w-md bg-slate-900 border border-slate-800 rounded-3xl p-8 shadow-2xl animate-in zoom-in-95 duration-200">
            <h2 className="text-2xl font-black mb-1">About You</h2>
            <p className="text-slate-500 text-sm mb-6">Helps Gemini remember who you are for a better social flow.</p>
            <form onSubmit={saveProfile} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] uppercase tracking-widest font-bold text-slate-400">Your Name</label>
                <input required name="name" defaultValue={userProfile?.name} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 focus:border-cyan-500 outline-none transition-colors" placeholder="e.g. Alex" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] uppercase tracking-widest font-bold text-slate-400">Our Relationship</label>
                <input required name="relationship" defaultValue={userProfile?.relationship} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 focus:border-cyan-500 outline-none transition-colors" placeholder="e.g. Best Friend, Mentor" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] uppercase tracking-widest font-bold text-slate-400">Interests (comma separated)</label>
                <input name="interests" defaultValue={userProfile?.interests.join(', ')} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 focus:border-cyan-500 outline-none transition-colors" placeholder="e.g. Music, Tech, Cooking" />
              </div>
              <div className="pt-4 flex space-x-3">
                <button type="submit" className="flex-1 bg-cyan-500 hover:bg-cyan-400 text-slate-950 font-bold py-4 rounded-2xl transition-all active:scale-95">
                  Save Changes
                </button>
                {userProfile && (
                   <button type="button" onClick={() => setIsProfileModalOpen(false)} className="px-6 py-4 bg-slate-800 rounded-2xl font-bold">
                    Cancel
                  </button>
                )}
              </div>
            </form>
          </div>
        </div>
      )}

      {/* History Drawer */}
      {isHistoryOpen && (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-slate-950/60 backdrop-blur-sm">
          <div className="w-full max-w-2xl h-[80vh] bg-slate-900 border-t border-slate-800 rounded-t-[3rem] p-8 shadow-2xl flex flex-col animate-in slide-in-from-bottom duration-300">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-black">Conversation Log</h2>
              <button onClick={() => setIsHistoryOpen(false)} className="w-10 h-10 rounded-full bg-slate-800 flex items-center justify-center text-slate-400">
                <i className="fas fa-times"></i>
              </button>
            </div>

            <div className="flex-1 overflow-y-auto space-y-4 pr-2">
              {history.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-slate-600 space-y-2 opacity-50">
                  <i className="fas fa-ghost text-4xl"></i>
                  <p>No history yet...</p>
                </div>
              ) : (
                history.map((msg, idx) => (
                  <div key={idx} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                    <span className="text-[8px] uppercase tracking-widest font-bold text-slate-600 mb-1 ml-1 mr-1">
                      {msg.role === 'user' ? userProfile?.name : 'Gemini'}
                    </span>
                    <div className={`max-w-[85%] px-4 py-3 rounded-2xl text-sm ${
                      msg.role === 'user' 
                        ? 'bg-cyan-500 text-slate-950 rounded-tr-none' 
                        : 'bg-slate-800 text-slate-200 rounded-tl-none'
                    }`}>
                      {msg.text}
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { decode, decodeAudioData, createPcmBlob } from './audioUtils';
import { UserProfile, ChatMessage, ConnectionStatus } from './types';
import Waveform from './components/Waveform';

const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

const App: React.FC = () => {
  // --- State ---
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('social_gemini_profile');
    return saved ? JSON.parse(saved) : null;
  });

  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [history, setHistory] = useState<ChatMessage[]>(() => {
    const saved = localStorage.getItem('social_gemini_history');
    return saved ? JSON.parse(saved) : [];
  });
  const [transcription, setTranscription] = useState<string>('');
  const [rmsInput, setRmsInput] = useState(0);
  const [rmsOutput, setRmsOutput] = useState(0);

  // Buffer for building full messages
  const currentTurnRef = useRef<{ user: string; model: string }>({ user: '', model: '' });

  // --- Refs ---
  const inputAudioCtxRef = useRef<AudioContext | null>(null);
  const outputAudioCtxRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  // Sync history
  useEffect(() => {
    localStorage.setItem('social_gemini_history', JSON.stringify(history));
  }, [history]);

  // Initial check for API Key environment
  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio?.hasSelectedApiKey) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(selected);
      } else {
        setHasApiKey(!!process.env.API_KEY);
      }
    };
    checkKey();
    if (!userProfile) setIsProfileModalOpen(true);
  }, [userProfile]);

  const handleOpenSelectKey = async () => {
    if (window.aistudio?.openSelectKey) {
      await window.aistudio.openSelectKey();
      // Assume success to proceed to connection
      setHasApiKey(true);
      setErrorMessage(null);
      setStatus(ConnectionStatus.DISCONNECTED);
    }
  };

  const stopAllAudio = useCallback(() => {
    sourcesRef.current.forEach(source => {
      try { source.stop(); } catch (e) {}
    });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
    setRmsOutput(0);
    setRmsInput(0);

    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    sessionRef.current = null;
  }, []);

  const connect = async () => {
    if (status === ConnectionStatus.CONNECTING) return;

    // Check key again before connecting
    let keyReady = hasApiKey;
    if (window.aistudio?.hasSelectedApiKey) {
      keyReady = await window.aistudio.hasSelectedApiKey();
    }

    if (!keyReady) {
      handleOpenSelectKey();
      return;
    }

    if (!userProfile) {
      setIsProfileModalOpen(true);
      return;
    }

    try {
      setErrorMessage(null);
      setStatus(ConnectionStatus.CONNECTING);

      // Initialize Contexts
      if (!inputAudioCtxRef.current) {
        inputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: INPUT_SAMPLE_RATE });
      }
      if (!outputAudioCtxRef.current) {
        outputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: OUTPUT_SAMPLE_RATE });
      }

      const input = inputAudioCtxRef.current;
      const output = outputAudioCtxRef.current;

      if (input.state === 'suspended') await input.resume();
      if (output.state === 'suspended') await output.resume();

      // IMPORTANT: Create fresh instance with current process.env.API_KEY
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const systemInstruction = `
        You are a socially intelligent, warm AI companion. 
        User's Name: ${userProfile.name}. 
        Interests: ${userProfile.interests.join(', ')}.

        Behavior:
        - Natural, warm conversation.
        - Don't be robotic. Be Reciprocal.
        - Concise responses (1-2 sentences) for low-latency voice feel.
      `;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
          },
          systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setStatus(ConnectionStatus.CONNECTED);
            const source = input.createMediaStreamSource(stream);
            const processor = input.createScriptProcessor(4096, 1, 1);
            processorRef.current = processor;

            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);

              let sum = 0;
              for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
              setRmsInput(Math.sqrt(sum / inputData.length));

              const pcmBlob = createPcmBlob(inputData);

              sessionPromise.then((session) => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(processor);
            processor.connect(input.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Audio Logic
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
              const audioBuffer = await decodeAudioData(decode(base64Audio), output, OUTPUT_SAMPLE_RATE, 1);
              const source = output.createBufferSource();
              source.buffer = audioBuffer;

              setRmsOutput(0.6);

              source.connect(output.destination);
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, output.currentTime);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;

              sourcesRef.current.add(source);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setRmsOutput(0);
              };
            }

            // Transcription
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              setTranscription(prev => (prev + ' ' + text).trim());
              currentTurnRef.current.user += text;
            }
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              setTranscription(prev => (prev + ' ' + text).trim());
              currentTurnRef.current.model += text;
            }

            if (message.serverContent?.turnComplete) {
              if (currentTurnRef.current.user || currentTurnRef.current.model) {
                setHistory(prev => [
                  ...prev,
                  { role: 'user', text: currentTurnRef.current.user || '(Audio)', timestamp: Date.now() },
                  { role: 'model', text: currentTurnRef.current.model || '(Audio)', timestamp: Date.now() }
                ].slice(-40));
              }
              currentTurnRef.current = { user: '', model: '' };
              setTranscription('');
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e: any) => {
            console.error('Session error:', e);
            const msg = (e?.message || e?.toString() || '').toLowerCase();

            if (msg.includes('requested entity was not found') || msg.includes('404')) {
              setErrorMessage("API Key missing or invalid for this model. Please re-select your AI Studio key.");
              setHasApiKey(false);
              handleOpenSelectKey(); // Prompt immediately
            } else if (msg.includes('network error')) {
              setErrorMessage("Connection lost. Please check your network.");
            } else {
              setErrorMessage("Something went wrong. Try again.");
            }

            setStatus(ConnectionStatus.ERROR);
            stopAllAudio();
          },
          onclose: () => {
            if (status !== ConnectionStatus.ERROR) setStatus(ConnectionStatus.DISCONNECTED);
            stopAllAudio();
          },
        },
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      setStatus(ConnectionStatus.ERROR);
      setErrorMessage("Failed to start session. Check your key.");
      stopAllAudio();
    }
  };

  const disconnect = () => {
    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch (e) {}
    }
    stopAllAudio();
    setStatus(ConnectionStatus.DISCONNECTED);
  };

  const saveProfile = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      relationship: formData.get('relationship') as string,
      interests: (formData.get('interests') as string).split(',').map(s => s.trim()).filter(Boolean),
    };
    setUserProfile(profile);
    localStorage.setItem('social_gemini_profile', JSON.stringify(profile));
    setIsProfileModalOpen(false);
  };

  return (
    <div className="flex flex-col h-screen bg-slate-950 text-slate-100 p-4 md:p-10 font-sans select-none overflow-hidden">
      {/* Header */}
      <header className="flex justify-between items-center shrink-0 z-10">
        <div>
          <h1 className="text-xl font-black tracking-tighter bg-gradient-to-r from-cyan-400 to-blue-500 bg-clip-text text-transparent">
            Social Gemini
          </h1>
          <div className="flex items-center space-x-2">
            <span className={`w-1.5 h-1.5 rounded-full ${status === ConnectionStatus.CONNECTED ? 'bg-cyan-400 animate-pulse' : status === ConnectionStatus.ERROR ? 'bg-red-500' : 'bg-slate-700'}`}></span>
            <span className="text-[9px] uppercase tracking-widest font-bold text-slate-500">
              {status}
            </span>
          </div>
        </div>

        <div className="flex space-x-2">
          {!hasApiKey && (
             <button 
              onClick={handleOpenSelectKey}
              className="px-3 py-1 text-[10px] font-bold bg-amber-500/20 text-amber-500 border border-amber-500/30 rounded-full animate-pulse"
            >
              Setup API Key
            </button>
          )}
          <button onClick={() => setIsHistoryOpen(true)} className="w-10 h-10 rounded-xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-400 hover:text-cyan-400 transition-all">
            <i className="fas fa-history text-sm"></i>
          </button>
          <button onClick={() => setIsProfileModalOpen(true)} className="w-10 h-10 rounded-xl bg-slate-900 border border-slate-800 flex items-center justify-center text-slate-400 hover:text-cyan-400 transition-all">
            <i className="fas fa-user-circle text-sm"></i>
          </button>
        </div>
      </header>

      {/* Main UI */}
      <main className="flex-1 flex flex-col items-center justify-center space-y-8 relative">
        <div className={`absolute w-72 h-72 bg-cyan-500/5 rounded-full blur-[120px] transition-opacity duration-1000 ${status === ConnectionStatus.CONNECTED ? 'opacity-100' : 'opacity-0'}`}></div>

        <div className="relative">
          <div className={`absolute -inset-10 bg-cyan-500/10 rounded-full blur-3xl transition-all duration-700 ${status === ConnectionStatus.CONNECTED ? 'scale-125 opacity-100' : 'scale-0 opacity-0'}`}></div>

          <button 
            onClick={status === ConnectionStatus.CONNECTED ? disconnect : connect}
            disabled={status === ConnectionStatus.CONNECTING}
            className={`relative w-44 h-44 rounded-full flex items-center justify-center border transition-all duration-500 shadow-2xl ${
              status === ConnectionStatus.CONNECTED 
                ? 'border-cyan-400/30 bg-slate-900/40 scale-105' 
                : status === ConnectionStatus.ERROR
                ? 'border-red-500/20 bg-slate-950'
                : 'border-slate-800 bg-slate-950'
            }`}
          >
            {status === ConnectionStatus.CONNECTING ? (
              <i className="fas fa-circle-notch fa-spin text-3xl text-cyan-400"></i>
            ) : status === ConnectionStatus.CONNECTED ? (
              <div className="flex items-center justify-center">
                 <div className="w-20 h-20 bg-cyan-400/20 rounded-full animate-ping absolute"></div>
                 <i className="fas fa-volume-up text-4xl text-cyan-400"></i>
              </div>
            ) : (
              <i className="fas fa-microphone text-slate-700 text-4xl group-hover:text-cyan-400 transition-colors"></i>
            )}
          </button>
        </div>

        <div className="w-full max-w-xs space-y-4 text-center">
          <Waveform isActive={status === ConnectionStatus.CONNECTED} color="#22d3ee" amplitude={Math.max(rmsInput, rmsOutput)} />

          <div className="min-h-[40px] px-4">
            {errorMessage ? (
              <p className="text-red-400 text-xs font-medium">
                {errorMessage}
              </p>
            ) : (
              <p className="text-slate-400 text-sm italic line-clamp-2">
                {transcription || (status === ConnectionStatus.CONNECTED ? "I'm listening..." : "Ready when you are") }
              </p>
            )}
          </div>
        </div>
      </main>

      {/* Footer Actions */}
      <footer className="shrink-0 flex justify-center pb-8">
        <button 
          onClick={status === ConnectionStatus.CONNECTED ? disconnect : connect}
          className={`flex items-center space-x-3 px-12 py-5 rounded-full font-bold shadow-xl active:scale-95 transition-all ${
            status === ConnectionStatus.CONNECTED
              ? 'bg-slate-900 border border-red-500/30 text-red-400'
              : 'bg-gradient-to-r from-cyan-600 to-blue-600 text-white'
          }`}
        >
          <i className={status === ConnectionStatus.CONNECTED ? 'fas fa-phone-slash' : 'fas fa-phone'}></i>
          <span>{status === ConnectionStatus.CONNECTED ? 'End Session' : 'Start Calling'}</span>
        </button>
      </footer>

      {/* History & Profile Modals (Same logic as provided) */}
      {isProfileModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-950/95 backdrop-blur-sm">
          <div className="w-full max-w-sm bg-slate-900 border border-slate-800 rounded-3xl p-8 shadow-2xl">
            <h2 className="text-2xl font-black mb-4">Your Profile</h2>
            <form onSubmit={saveProfile} className="space-y-4">
              <input required name="name" defaultValue={userProfile?.name} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 focus:border-cyan-500 outline-none" placeholder="Your Name" />
              <input name="interests" defaultValue={userProfile?.interests.join(', ')} className="w-full bg-slate-950 border border-slate-800 rounded-xl px-4 py-3 focus:border-cyan-500 outline-none" placeholder="Interests (Music, Tech, etc)" />
              <button type="submit" className="w-full bg-cyan-500 hover:bg-cyan-400 text-slate-950 font-bold py-4 rounded-xl transition-all">
                Save & Continue
              </button>
            </form>
          </div>
        </div>
      )}

      {isHistoryOpen && (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-slate-950/60 backdrop-blur-sm">
          <div className="w-full max-w-2xl h-[70vh] bg-slate-900 border-t border-slate-800 rounded-t-[3rem] p-8 shadow-2xl flex flex-col animate-in slide-in-from-bottom duration-300">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-black">Memory</h2>
              <button onClick={() => setIsHistoryOpen(false)} className="w-10 h-10 rounded-full bg-slate-800 flex items-center justify-center text-slate-400">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <div className="flex-1 overflow-y-auto space-y-4 pb-4">
              {history.map((msg, idx) => (
                <div key={idx} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                  <div className={`max-w-[85%] px-4 py-3 rounded-2xl text-sm ${msg.role === 'user' ? 'bg-cyan-500 text-slate-950' : 'bg-slate-800 text-slate-200'}`}>
                    {msg.text}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export interface UserProfile {
  name: string;
  relationship: string;
  interests: string[];
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export enum ConnectionStatus {
  DISCONNECTED = 'DISCONNECTED',
  CONNECTING = 'CONNECTING',
  CONNECTED = 'CONNECTED',
  RECONNECTING = 'RECONNECTING',
  ERROR = 'ERROR'
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { decode, decodeAudioData, createPcmBlob } from './audioUtils';
import { UserProfile, ChatMessage, ConnectionStatus } from './types';
import Waveform from './components/Waveform';

const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;
const MAX_RECONNECT_ATTEMPTS = 3;

const App: React.FC = () => {
  // --- State ---
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [isWeakSignal, setIsWeakSignal] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('social_gemini_profile');
    return saved ? JSON.parse(saved) : null;
  });

  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [history, setHistory] = useState<ChatMessage[]>(() => {
    const saved = localStorage.getItem('social_gemini_history');
    return saved ? JSON.parse(saved) : [];
  });
  const [transcription, setTranscription] = useState<string>('');
  const [rmsInput, setRmsInput] = useState(0);
  const [rmsOutput, setRmsOutput] = useState(0);

  // Buffer refs
  const currentTurnRef = useRef<{ user: string; model: string }>({ user: '', model: '' });
  const reconnectAttemptsRef = useRef(0);
  const lastSignalTimeRef = useRef(Date.now());

  // --- Refs ---
  const inputAudioCtxRef = useRef<AudioContext | null>(null);
  const outputAudioCtxRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    localStorage.setItem('social_gemini_history', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio?.hasSelectedApiKey) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(selected);
      } else {
        setHasApiKey(!!process.env.API_KEY);
      }
    };
    checkKey();
    if (!userProfile) setIsProfileModalOpen(true);

    // Watch for network stalls
    const interval = setInterval(() => {
      if (status === ConnectionStatus.CONNECTED && Date.now() - lastSignalTimeRef.current > 15000) {
        setIsWeakSignal(true);
      } else {
        setIsWeakSignal(false);
      }
    }, 5000);
    return () => clearInterval(interval);
  }, [userProfile, status]);

  const handleOpenSelectKey = async () => {
    if (window.aistudio?.openSelectKey) {
      await window.aistudio.openSelectKey();
      setHasApiKey(true);
      setErrorMessage(null);
    }
  };

  const stopAllAudio = useCallback(() => {
    sourcesRef.current.forEach(source => {
      try { source.stop(); } catch (e) {}
    });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
    setRmsOutput(0);
    setRmsInput(0);

    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    sessionRef.current = null;
  }, []);

  const connect = async (isReconnecting = false) => {
    if (status === ConnectionStatus.CONNECTING && !isReconnecting) return;

    let keyReady = hasApiKey;
    if (window.aistudio?.hasSelectedApiKey) {
      keyReady = await window.aistudio.hasSelectedApiKey();
    }

    if (!keyReady) {
      handleOpenSelectKey();
      return;
    }

    if (!userProfile) {
      setIsProfileModalOpen(true);
      return;
    }

    try {
      setErrorMessage(null);
      setStatus(isReconnecting ? ConnectionStatus.RECONNECTING : ConnectionStatus.CONNECTING);

      if (!inputAudioCtxRef.current) {
        inputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: INPUT_SAMPLE_RATE });
      }
      if (!outputAudioCtxRef.current) {
        outputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: OUTPUT_SAMPLE_RATE });
      }

      const input = inputAudioCtxRef.current;
      const output = outputAudioCtxRef.current;

      if (input.state === 'suspended') await input.resume();
      if (output.state === 'suspended') await output.resume();

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const systemInstruction = `
        You are a warm, patient AI companion. 
        User's Name: ${userProfile.name}. 
        User's Environment: On a farm with poor internet. 

        Behavior:
        - Be patient. If there are gaps, don't repeat yourself excessively.
        - Keep responses concise (1-2 sentences) to save bandwidth.
        - Warm, Reciprocal, Social.
      `;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
          },
          systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setStatus(ConnectionStatus.CONNECTED);
            reconnectAttemptsRef.current = 0;
            lastSignalTimeRef.current = Date.now();
            const source = input.createMediaStreamSource(stream);
            const processor = input.createScriptProcessor(4096, 1, 1);
            processorRef.current = processor;

            processor.onaudioprocess = (e) => {
              if (status !== ConnectionStatus.CONNECTED && status !== ConnectionStatus.RECONNECTING) return;
              const inputData = e.inputBuffer.getChannelData(0);

              let sum = 0;
              for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
              setRmsInput(Math.sqrt(sum / inputData.length));

              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(processor);
            processor.connect(input.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            lastSignalTimeRef.current = Date.now();

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
              const audioBuffer = await decodeAudioData(decode(base64Audio), output, OUTPUT_SAMPLE_RATE, 1);
              const source = output.createBufferSource();
              source.buffer = audioBuffer;
              setRmsOutput(0.6);
              source.connect(output.destination);
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, output.currentTime);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setRmsOutput(0);
              };
            }

            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              setTranscription(prev => (prev + ' ' + text).trim());
              currentTurnRef.current.user += text;
            }
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              setTranscription(prev => (prev + ' ' + text).trim());
              currentTurnRef.current.model += text;
            }

            if (message.serverContent?.turnComplete) {
              if (currentTurnRef.current.user || currentTurnRef.current.model) {
                setHistory(prev => [
                  ...prev,
                  { role: 'user', text: currentTurnRef.current.user || '(Speech)', timestamp: Date.now() },
                  { role: 'model', text: currentTurnRef.current.model || '(Speech)', timestamp: Date.now() }
                ].slice(-30));
              }
              currentTurnRef.current = { user: '', model: '' };
              setTranscription('');
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e: any) => {
            console.error('Session error:', e);
            const msg = (e?.message || e?.toString() || '').toLowerCase();

            if (msg.includes('requested entity was not found') || msg.includes('404')) {
              setErrorMessage("Model not found. Project may lack API Pro permissions.");
              setHasApiKey(false);
              setStatus(ConnectionStatus.ERROR);
              stopAllAudio();
            } else if (reconnectAttemptsRef.current < MAX_RECONNECT_ATTEMPTS) {
              reconnectAttemptsRef.current++;
              setErrorMessage(`Connection lost. Retrying (${reconnectAttemptsRef.current}/${MAX_RECONNECT_ATTEMPTS})...`);
              setTimeout(() => connect(true), 2000);
            } else {
              setErrorMessage("Poor signal. Check your cell service and try again.");
              setStatus(ConnectionStatus.ERROR);
              stopAllAudio();
            }
          },
          onclose: () => {
            if (status !== ConnectionStatus.ERROR && status !== ConnectionStatus.CONNECTING) {
              if (reconnectAttemptsRef.current < MAX_RECONNECT_ATTEMPTS) {
                reconnectAttemptsRef.current++;
                connect(true);
              } else {
                setStatus(ConnectionStatus.DISCONNECTED);
                stopAllAudio();
              }
            }
          },
        },
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      console.error('Connection catch:', err);
      setStatus(ConnectionStatus.ERROR);
      setErrorMessage("Failed to connect. Low signal?");
      stopAllAudio();
    }
  };

  const disconnect = () => {
    reconnectAttemptsRef.current = MAX_RECONNECT_ATTEMPTS; // Prevent auto-reconnect
    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch (e) {}
    }
    stopAllAudio();
    setStatus(ConnectionStatus.DISCONNECTED);
  };

  const saveProfile = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      relationship: formData.get('relationship') as string,
      interests: (formData.get('interests') as string).split(',').map(s => s.trim()).filter(Boolean),
    };
    setUserProfile(profile);
    localStorage.setItem('social_gemini_profile', JSON.stringify(profile));
    setIsProfileModalOpen(false);
  };

  return (
    <div className="flex flex-col h-screen bg-[#020617] text-slate-100 p-4 md:p-10 font-sans select-none overflow-hidden">
      {/* Network Header */}
      <header className="flex justify-between items-center shrink-0 z-10">
        <div>
          <h1 className="text-xl font-black tracking-tighter bg-gradient-to-r from-cyan-400 to-indigo-500 bg-clip-text text-transparent">
            Social Gemini
          </h1>
          <div className="flex items-center space-x-2">
            <span className={`w-1.5 h-1.5 rounded-full ${
              status === ConnectionStatus.CONNECTED ? 'bg-cyan-400 animate-pulse' : 
              status === ConnectionStatus.RECONNECTING ? 'bg-amber-400 animate-bounce' :
              status === ConnectionStatus.ERROR ? 'bg-red-500' : 'bg-slate-700'
            }`}></span>
            <span className="text-[10px] uppercase tracking-widest font-bold text-slate-500">
              {status === ConnectionStatus.RECONNECTING ? 'Reconnecting...' : status}
            </span>
            {isWeakSignal && (
              <span className="text-[10px] bg-amber-500/10 text-amber-500 px-2 py-0.5 rounded border border-amber-500/20 animate-pulse">
                Weak Signal
              </span>
            )}
          </div>
        </div>

        <div className="flex space-x-2">
          {!hasApiKey && (
             <button onClick={handleOpenSelectKey} className="px-3 py-1.5 text-[10px] font-bold bg-amber-500 text-slate-950 rounded-full">
              Fix API Key
            </button>
          )}
          <button onClick={() => setIsHistoryOpen(true)} className="w-10 h-10 rounded-2xl bg-slate-900/50 border border-white/5 flex items-center justify-center text-slate-400 hover:text-cyan-400 transition-all shadow-lg">
            <i className="fas fa-history text-sm"></i>
          </button>
          <button onClick={() => setIsProfileModalOpen(true)} className="w-10 h-10 rounded-2xl bg-slate-900/50 border border-white/5 flex items-center justify-center text-slate-400 hover:text-cyan-400 transition-all shadow-lg">
            <i className="fas fa-user-circle text-sm"></i>
          </button>
        </div>
      </header>

      {/* Main Experience */}
      <main className="flex-1 flex flex-col items-center justify-center space-y-12 relative">
        <div className={`absolute w-[500px] h-[500px] bg-cyan-500/5 rounded-full blur-[150px] transition-opacity duration-1000 ${status === ConnectionStatus.CONNECTED ? 'opacity-100' : 'opacity-0'}`}></div>

        <div className="relative group">
          <div className={`absolute -inset-16 bg-cyan-500/5 rounded-full blur-[80px] transition-all duration-1000 ${status === ConnectionStatus.CONNECTED ? 'scale-150 opacity-100' : 'scale-0 opacity-0'}`}></div>

          <button 
            onClick={status === ConnectionStatus.CONNECTED || status === ConnectionStatus.RECONNECTING ? disconnect : () => connect()}
            disabled={status === ConnectionStatus.CONNECTING}
            className={`relative w-48 h-48 rounded-[3rem] flex items-center justify-center border transition-all duration-700 shadow-[0_0_50px_rgba(0,0,0,0.5)] ${
              status === ConnectionStatus.CONNECTED 
                ? 'border-cyan-400/20 bg-slate-900/40 backdrop-blur-xl rotate-[10deg]' 
                : status === ConnectionStatus.ERROR
                ? 'border-red-500/20 bg-slate-950 rotate-0'
                : 'border-white/5 bg-slate-950 rotate-0'
            }`}
          >
            {status === ConnectionStatus.CONNECTING || status === ConnectionStatus.RECONNECTING ? (
              <div className="flex flex-col items-center space-y-2">
                <i className="fas fa-circle-notch fa-spin text-3xl text-cyan-400"></i>
                <span className="text-[10px] font-bold text-cyan-400/60 tracking-widest">SIGNAL...</span>
              </div>
            ) : status === ConnectionStatus.CONNECTED ? (
              <div className="flex items-center justify-center -rotate-[10deg]">
                 <div className="w-24 h-24 bg-cyan-500/20 rounded-full animate-ping absolute"></div>
                 <i className="fas fa-satellite-dish text-5xl text-cyan-400"></i>
              </div>
            ) : (
              <i className="fas fa-microphone text-slate-800 text-5xl group-hover:text-cyan-400 transition-colors"></i>
            )}
          </button>
        </div>

        <div className="w-full max-w-sm space-y-8 text-center px-4">
          <div className="h-12 overflow-hidden">
            <Waveform isActive={status === ConnectionStatus.CONNECTED} color="#22d3ee" amplitude={Math.max(rmsInput, rmsOutput)} />
          </div>

          <div className="min-h-[60px] flex flex-col items-center justify-center px-6">
            {errorMessage ? (
              <div className="animate-in fade-in zoom-in duration-300">
                 <p className="text-red-400 text-xs font-black uppercase tracking-wider bg-red-500/10 px-4 py-2 rounded-full border border-red-500/20">
                  {errorMessage}
                </p>
                {status === ConnectionStatus.ERROR && (
                   <button onClick={() => connect()} className="mt-4 text-cyan-400 text-[10px] font-bold underline">Try Again</button>
                )}
              </div>
            ) : (
              <p className="text-slate-500 text-sm font-medium italic leading-relaxed animate-in slide-in-from-bottom-2 duration-700">
                {transcription || (status === ConnectionStatus.CONNECTED ? "Listening on the farm..." : status === ConnectionStatus.CONNECTING ? "Optimizing link..." : "Ready for a chat") }
              </p>
            )}
          </div>
        </div>
      </main>

      {/* Persistent Call Button */}
      <footer className="shrink-0 flex justify-center pb-12">
        <button 
          onClick={status === ConnectionStatus.CONNECTED || status === ConnectionStatus.RECONNECTING ? disconnect : () => connect()}
          className={`group flex items-center space-x-4 px-14 py-6 rounded-[2rem] font-black text-sm tracking-widest uppercase shadow-2xl active:scale-95 transition-all duration-500 ${
            status === ConnectionStatus.CONNECTED || status === ConnectionStatus.RECONNECTING
              ? 'bg-red-500/10 border border-red-500/30 text-red-500 hover:bg-red-500 hover:text-white'
              : 'bg-gradient-to-br from-cyan-500 to-indigo-600 text-white hover:shadow-cyan-500/40'
          }`}
        >
          <i className={status === ConnectionStatus.CONNECTED ? 'fas fa-phone-slash' : 'fas fa-phone'}></i>
          <span>{status === ConnectionStatus.CONNECTED ? 'End Chat' : 'Start Calling'}</span>
        </button>
      </footer>

      {/* History & Profile Modals */}
      {isProfileModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-[#020617]/95 backdrop-blur-xl">
          <div className="w-full max-w-sm bg-slate-900/50 border border-white/5 rounded-[3rem] p-10 shadow-3xl">
            <h2 className="text-3xl font-black mb-2 tracking-tighter">Profile</h2>
            <p className="text-slate-500 text-xs mb-8 font-medium">This helps Gemini stay consistent when the signal drops.</p>
            <form onSubmit={saveProfile} className="space-y-6">
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-1">Name</label>
                <input required name="name" defaultValue={userProfile?.name} className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-4 focus:border-cyan-500 outline-none transition-all text-sm" placeholder="Alex" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-1">Interests</label>
                <input name="interests" defaultValue={userProfile?.interests.join(', ')} className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-4 focus:border-cyan-500 outline-none transition-all text-sm" placeholder="Farming, Tech, Coffee" />
              </div>
              <button type="submit" className="w-full bg-white text-black font-black py-5 rounded-[2rem] transition-all active:scale-95 shadow-lg">
                SAVE & CHAT
              </button>
            </form>
          </div>
        </div>
      )}

      {isHistoryOpen && (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/80 backdrop-blur-sm">
          <div className="w-full max-w-2xl h-[75vh] bg-[#0f172a] border-t border-white/10 rounded-t-[4rem] p-10 shadow-3xl flex flex-col animate-in slide-in-from-bottom duration-500">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black tracking-tighter">Memory</h2>
              <button onClick={() => setIsHistoryOpen(false)} className="w-12 h-12 rounded-full bg-slate-800/50 flex items-center justify-center text-slate-400">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <div className="flex-1 overflow-y-auto space-y-6 pb-10 scrollbar-hide">
              {history.map((msg, idx) => (
                <div key={idx} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                  <div className={`max-w-[85%] px-6 py-4 rounded-[2rem] text-sm font-medium ${msg.role === 'user' ? 'bg-cyan-500 text-slate-950 rounded-tr-none' : 'bg-slate-800/50 text-slate-200 rounded-tl-none border border-white/5'}`}>
                    {msg.text}
                  </div>
                  <span className="text-[9px] font-bold text-slate-600 mt-2 px-2">
                    {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </span>
                </div>
              ))}
              {history.length === 0 && (
                <div className="flex flex-col items-center justify-center h-full text-slate-600 space-y-4">
                   <i className="fas fa-brain text-4xl opacity-20"></i>
                   <p className="text-xs font-bold tracking-widest uppercase">No memories yet</p>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { decode, decodeAudioData, createPcmBlob } from './audioUtils';
import { UserProfile, ChatMessage, ConnectionStatus } from './types';
import Waveform from './components/Waveform';

const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;
const MAX_RECONNECT_ATTEMPTS = 5; // Increased for poor cell service

const App: React.FC = () => {
  // --- State ---
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [isWeakSignal, setIsWeakSignal] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('social_gemini_profile');
    return saved ? JSON.parse(saved) : null;
  });

  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [history, setHistory] = useState<ChatMessage[]>(() => {
    const saved = localStorage.getItem('social_gemini_history');
    return saved ? JSON.parse(saved) : [];
  });
  const [transcription, setTranscription] = useState<string>('');
  const [rmsInput, setRmsInput] = useState(0);
  const [rmsOutput, setRmsOutput] = useState(0);

  // Buffer refs
  const currentTurnRef = useRef<{ user: string; model: string }>({ user: '', model: '' });
  const reconnectAttemptsRef = useRef(0);
  const lastSignalTimeRef = useRef(Date.now());

  // --- Refs ---
  const inputAudioCtxRef = useRef<AudioContext | null>(null);
  const outputAudioCtxRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    localStorage.setItem('social_gemini_history', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio?.hasSelectedApiKey) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(selected);
      } else {
        setHasApiKey(!!process.env.API_KEY);
      }
    };
    checkKey();
    if (!userProfile) setIsProfileModalOpen(true);

    const interval = setInterval(() => {
      if (status === ConnectionStatus.CONNECTED && Date.now() - lastSignalTimeRef.current > 12000) {
        setIsWeakSignal(true);
      } else {
        setIsWeakSignal(false);
      }
    }, 4000);
    return () => clearInterval(interval);
  }, [userProfile, status]);

  const handleOpenSelectKey = async () => {
    if (window.aistudio?.openSelectKey) {
      await window.aistudio.openSelectKey();
      // Assume success and refresh state
      setHasApiKey(true);
      setErrorMessage(null);
    }
  };

  const stopAllAudio = useCallback(() => {
    sourcesRef.current.forEach(source => {
      try { source.stop(); } catch (e) {}
    });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
    setRmsOutput(0);
    setRmsInput(0);

    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    sessionRef.current = null;
  }, []);

  const connect = async (isReconnecting = false) => {
    if (status === ConnectionStatus.CONNECTING && !isReconnecting) return;

    // Check if key is selected (mandatory for Pro/Veo/Live often)
    if (window.aistudio?.hasSelectedApiKey) {
      const selected = await window.aistudio.hasSelectedApiKey();
      if (!selected) {
        await handleOpenSelectKey();
      }
    }

    if (!userProfile) {
      setIsProfileModalOpen(true);
      return;
    }

    try {
      setErrorMessage(null);
      setStatus(isReconnecting ? ConnectionStatus.RECONNECTING : ConnectionStatus.CONNECTING);

      if (!inputAudioCtxRef.current) {
        inputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: INPUT_SAMPLE_RATE });
      }
      if (!outputAudioCtxRef.current) {
        outputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: OUTPUT_SAMPLE_RATE });
      }

      const input = inputAudioCtxRef.current;
      const output = outputAudioCtxRef.current;

      if (input.state === 'suspended') await input.resume();
      if (output.state === 'suspended') await output.resume();

      // IMPORTANT: Always new instance to get updated API_KEY from dialog
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const systemInstruction = `
        You are a warm, patient AI companion. 
        User's Name: ${userProfile.name}. 
        User's Context: Using AI Studio Pro on a farm with spotty cell service.

        Behavior:
        - Be patient. If signal drops, don't repeat yourself.
        - Keep responses concise (1-2 sentences) to minimize packet loss.
        - Social, Reciprocal, and supportive of the farm life.
      `;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
          },
          systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setStatus(ConnectionStatus.CONNECTED);
            reconnectAttemptsRef.current = 0;
            lastSignalTimeRef.current = Date.now();

            const source = input.createMediaStreamSource(stream);
            const processor = input.createScriptProcessor(4096, 1, 1);
            processorRef.current = processor;

            processor.onaudioprocess = (e) => {
              if (status !== ConnectionStatus.CONNECTED && status !== ConnectionStatus.RECONNECTING) return;
              const inputData = e.inputBuffer.getChannelData(0);

              let sum = 0;
              for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
              setRmsInput(Math.sqrt(sum / inputData.length));

              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(processor);
            processor.connect(input.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            lastSignalTimeRef.current = Date.now();

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
              const audioBuffer = await decodeAudioData(decode(base64Audio), output, OUTPUT_SAMPLE_RATE, 1);
              const source = output.createBufferSource();
              source.buffer = audioBuffer;
              setRmsOutput(0.6);
              source.connect(output.destination);
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, output.currentTime);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setRmsOutput(0);
              };
            }

            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              setTranscription(prev => (prev + ' ' + text).trim());
              currentTurnRef.current.user += text;
            }
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              setTranscription(prev => (prev + ' ' + text).trim());
              currentTurnRef.current.model += text;
            }

            if (message.serverContent?.turnComplete) {
              if (currentTurnRef.current.user || currentTurnRef.current.model) {
                setHistory(prev => [
                  ...prev,
                  { role: 'user', text: currentTurnRef.current.user || '(Speech)', timestamp: Date.now() },
                  { role: 'model', text: currentTurnRef.current.model || '(Speech)', timestamp: Date.now() }
                ].slice(-30));
              }
              currentTurnRef.current = { user: '', model: '' };
              setTranscription('');
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e: any) => {
            console.error('Session error:', e);
            const msg = (e?.message || e?.toString() || '').toLowerCase();

            if (msg.includes('requested entity was not found') || msg.includes('404')) {
              setErrorMessage("AI Studio Pro access required. Check your key.");
              setHasApiKey(false);
              setStatus(ConnectionStatus.ERROR);
              handleOpenSelectKey(); // Prompt immediately for new key
              stopAllAudio();
            } else if (reconnectAttemptsRef.current < MAX_RECONNECT_ATTEMPTS) {
              reconnectAttemptsRef.current++;
              setErrorMessage(`Connection lost. Reconnecting... (${reconnectAttemptsRef.current}/${MAX_RECONNECT_ATTEMPTS})`);
              setTimeout(() => connect(true), 3000);
            } else {
              setErrorMessage("Link failed. Check farm signal.");
              setStatus(ConnectionStatus.ERROR);
              stopAllAudio();
            }
          },
          onclose: () => {
            if (status !== ConnectionStatus.ERROR && status !== ConnectionStatus.CONNECTING) {
              if (reconnectAttemptsRef.current < MAX_RECONNECT_ATTEMPTS) {
                reconnectAttemptsRef.current++;
                connect(true);
              } else {
                setStatus(ConnectionStatus.DISCONNECTED);
                stopAllAudio();
              }
            }
          },
        },
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      console.error('Connection catch:', err);
      setStatus(ConnectionStatus.ERROR);
      setErrorMessage("Failed to start session.");
      stopAllAudio();
    }
  };

  const disconnect = () => {
    reconnectAttemptsRef.current = MAX_RECONNECT_ATTEMPTS; 
    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch (e) {}
    }
    stopAllAudio();
    setStatus(ConnectionStatus.DISCONNECTED);
  };

  const saveProfile = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      relationship: formData.get('relationship') as string,
      interests: (formData.get('interests') as string).split(',').map(s => s.trim()).filter(Boolean),
    };
    setUserProfile(profile);
    localStorage.setItem('social_gemini_profile', JSON.stringify(profile));
    setIsProfileModalOpen(false);
  };

  return (
    <div className="flex flex-col h-screen bg-[#020617] text-slate-100 p-4 md:p-10 font-sans select-none overflow-hidden">
      {/* Network Header */}
      <header className="flex justify-between items-center shrink-0 z-10">
        <div className="flex flex-col">
          <h1 className="text-xl font-black tracking-tighter bg-gradient-to-r from-cyan-400 to-indigo-500 bg-clip-text text-transparent">
            Social Gemini
          </h1>
          <div className="flex items-center space-x-2 mt-1">
            <span className={`w-2 h-2 rounded-full ${
              status === ConnectionStatus.CONNECTED ? 'bg-cyan-400 animate-pulse' : 
              status === ConnectionStatus.RECONNECTING ? 'bg-amber-400 animate-bounce' :
              status === ConnectionStatus.ERROR ? 'bg-red-500' : 'bg-slate-700'
            }`}></span>
            <span className="text-[10px] uppercase tracking-widest font-bold text-slate-500">
              {status}
            </span>
            {isWeakSignal && (
              <span className="text-[9px] font-black text-amber-500 animate-pulse bg-amber-500/10 px-1.5 py-0.5 rounded border border-amber-500/20">
                LOW SIGNAL
              </span>
            )}
          </div>
        </div>

        <div className="flex space-x-2">
           <button 
              onClick={handleOpenSelectKey} 
              className={`px-3 py-1.5 text-[10px] font-bold rounded-xl border transition-all ${
                hasApiKey ? 'bg-slate-900 border-white/10 text-slate-400' : 'bg-cyan-500 border-cyan-400 text-slate-950 animate-pulse'
              }`}
            >
              <i className="fas fa-key mr-2"></i>
              {hasApiKey ? 'AI STUDIO PRO' : 'SET PRO KEY'}
            </button>

          <button onClick={() => setIsHistoryOpen(true)} className="w-10 h-10 rounded-xl bg-slate-900 border border-white/5 flex items-center justify-center text-slate-400 hover:text-cyan-400">
            <i className="fas fa-history text-sm"></i>
          </button>
        </div>
      </header>

      {/* Main Experience */}
      <main className="flex-1 flex flex-col items-center justify-center space-y-12 relative">
        <div className={`absolute w-[400px] h-[400px] bg-cyan-500/5 rounded-full blur-[100px] transition-opacity duration-1000 ${status === ConnectionStatus.CONNECTED ? 'opacity-100' : 'opacity-0'}`}></div>

        <div className="relative group">
          <div className={`absolute -inset-12 bg-cyan-500/5 rounded-full blur-[60px] transition-all duration-1000 ${status === ConnectionStatus.CONNECTED ? 'scale-150 opacity-100' : 'scale-0 opacity-0'}`}></div>

          <button 
            onClick={status === ConnectionStatus.CONNECTED || status === ConnectionStatus.RECONNECTING ? disconnect : () => connect()}
            disabled={status === ConnectionStatus.CONNECTING}
            className={`relative w-48 h-48 rounded-[3.5rem] flex flex-col items-center justify-center border transition-all duration-700 shadow-3xl ${
              status === ConnectionStatus.CONNECTED 
                ? 'border-cyan-400/30 bg-slate-900/40 backdrop-blur-2xl rotate-3' 
                : status === ConnectionStatus.ERROR
                ? 'border-red-500/20 bg-slate-950'
                : 'border-white/10 bg-slate-950 hover:border-cyan-500/40'
            }`}
          >
            {status === ConnectionStatus.CONNECTING || status === ConnectionStatus.RECONNECTING ? (
              <div className="flex flex-col items-center space-y-3">
                <i className="fas fa-satellite fa-spin text-3xl text-cyan-400"></i>
                <span className="text-[9px] font-black text-cyan-400/60 tracking-widest uppercase">Linking...</span>
              </div>
            ) : status === ConnectionStatus.CONNECTED ? (
              <div className="flex flex-col items-center space-y-2 -rotate-3">
                 <div className="w-20 h-20 bg-cyan-500/20 rounded-full animate-ping absolute"></div>
                 <i className="fas fa-broadcast-tower text-5xl text-cyan-400"></i>
              </div>
            ) : (
              <i className="fas fa-microphone text-slate-800 text-5xl group-hover:text-cyan-400 transition-colors"></i>
            )}
          </button>
        </div>

        <div className="w-full max-w-sm space-y-6 text-center px-4">
          <div className="h-10 overflow-hidden">
            <Waveform isActive={status === ConnectionStatus.CONNECTED} color="#22d3ee" amplitude={Math.max(rmsInput, rmsOutput)} />
          </div>

          <div className="min-h-[60px] flex flex-col items-center justify-center px-6">
            {errorMessage ? (
              <div className="animate-in fade-in zoom-in duration-300">
                 <p className="text-red-400 text-[11px] font-bold uppercase tracking-wider bg-red-500/10 px-4 py-2 rounded-full border border-red-500/20">
                  {errorMessage}
                </p>
                <a 
                  href="https://ai.google.dev/gemini-api/docs/billing" 
                  target="_blank" 
                  rel="noopener noreferrer"
                  className="mt-3 block text-[10px] text-slate-500 underline hover:text-cyan-400"
                >
                  Check Billing & Quota Setup
                </a>
              </div>
            ) : (
              <p className="text-slate-500 text-sm font-medium italic leading-relaxed">
                {transcription || (status === ConnectionStatus.CONNECTED ? "Listening on the farm..." : "Ready to chat") }
              </p>
            )}
          </div>
        </div>
      </main>

      {/* Footer Call Controls */}
      <footer className="shrink-0 flex flex-col items-center pb-12 space-y-4">
        <button 
          onClick={status === ConnectionStatus.CONNECTED || status === ConnectionStatus.RECONNECTING ? disconnect : () => connect()}
          className={`flex items-center space-x-4 px-16 py-6 rounded-[2.5rem] font-black text-xs tracking-[0.2em] uppercase shadow-2xl active:scale-95 transition-all duration-500 ${
            status === ConnectionStatus.CONNECTED || status === ConnectionStatus.RECONNECTING
              ? 'bg-red-500/10 border border-red-500/30 text-red-500'
              : 'bg-gradient-to-br from-cyan-500 to-indigo-600 text-white shadow-cyan-900/40'
          }`}
        >
          <i className={status === ConnectionStatus.CONNECTED ? 'fas fa-phone-slash' : 'fas fa-phone'}></i>
          <span>{status === ConnectionStatus.CONNECTED ? 'End Session' : 'Call Social AI'}</span>
        </button>

        {!hasApiKey && (
          <p className="text-[9px] text-slate-600 font-bold uppercase tracking-widest text-center px-10 leading-loose">
            AI Studio Pro key required for stable Live Audio. <br/>
            <a href="https://ai.google.dev/gemini-api/docs/billing" className="text-cyan-600 underline">Enable billing</a> in your project first.
          </p>
        )}
      </footer>

      {/* Profile Setup Modal */}
      {isProfileModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-[#020617]/95 backdrop-blur-xl">
          <div className="w-full max-w-sm bg-slate-900/50 border border-white/5 rounded-[3rem] p-10 shadow-3xl">
            <h2 className="text-2xl font-black mb-1 tracking-tighter">Your Profile</h2>
            <p className="text-slate-500 text-[10px] mb-8 font-bold uppercase tracking-widest leading-relaxed">Persists even if signal drops</p>
            <form onSubmit={saveProfile} className="space-y-6">
              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1">Name</label>
                <input required name="name" defaultValue={userProfile?.name} className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-4 focus:border-cyan-500 outline-none transition-all text-sm" placeholder="e.g. Farmer Sam" />
              </div>
              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1">Interests</label>
                <input name="interests" defaultValue={userProfile?.interests.join(', ')} className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-4 focus:border-cyan-500 outline-none transition-all text-sm" placeholder="e.g. Livestock, Tech, Weather" />
              </div>
              <button type="submit" className="w-full bg-cyan-500 text-slate-950 font-black py-5 rounded-[2rem] transition-all active:scale-95 shadow-xl hover:bg-cyan-400">
                SAVE & START
              </button>
            </form>
          </div>
        </div>
      )}

      {/* History Drawer */}
      {isHistoryOpen && (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/80 backdrop-blur-sm">
          <div className="w-full max-w-2xl h-[75vh] bg-[#0f172a] border-t border-white/10 rounded-t-[4rem] p-10 shadow-3xl flex flex-col animate-in slide-in-from-bottom duration-500">
            <div className="flex justify-between items-center mb-8">
              <div className="flex flex-col">
                <h2 className="text-2xl font-black tracking-tighter">Call History</h2>
                <span className="text-[9px] font-black text-slate-500 uppercase tracking-[0.2em] mt-1">Local Memory Only</span>
              </div>
              <button onClick={() => setIsHistoryOpen(false)} className="w-12 h-12 rounded-2xl bg-slate-800/50 flex items-center justify-center text-slate-400 hover:text-white transition-colors">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <div className="flex-1 overflow-y-auto space-y-6 pb-10 scrollbar-hide">
              {history.map((msg, idx) => (
                <div key={idx} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                  <div className={`max-w-[85%] px-6 py-4 rounded-[2rem] text-sm font-medium ${msg.role === 'user' ? 'bg-cyan-500 text-slate-950 rounded-tr-none shadow-lg' : 'bg-slate-800/50 text-slate-200 rounded-tl-none border border-white/5 shadow-md'}`}>
                    {msg.text}
                  </div>
                  <span className="text-[8px] font-black text-slate-600 mt-2 px-2 uppercase tracking-widest">
                    {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </span>
                </div>
              ))}
              {history.length === 0 && (
                <div className="flex flex-col items-center justify-center h-full text-slate-700 space-y-4">
                   <i className="fas fa-microchip text-4xl opacity-10"></i>
                   <p className="text-[10px] font-black tracking-[0.3em] uppercase opacity-40">No Logged Speech</p>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function encode(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  // Use byteOffset and byteLength to be safe if the buffer is shared or has padding
  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, data.byteLength / 2);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function createPcmBlob(data: Float32Array): { data: string; mimeType: string } {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    // Clamp to valid Int16 range
    int16[i] = Math.max(-32768, Math.min(32767, data[i] * 32768));
  }
  return {
    // Return the base64 encoded raw bytes of the Int16Array
    data: encode(new Uint8Array(int16.buffer, int16.byteOffset, int16.byteLength)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { decode, decodeAudioData, createPcmBlob } from './audioUtils';
import { UserProfile, ChatMessage, ConnectionStatus } from './types';
import Waveform from './components/Waveform';

const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;
const MAX_RECONNECT_ATTEMPTS = 5;

const App: React.FC = () => {
  // --- State ---
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [isWeakSignal, setIsWeakSignal] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('social_gemini_profile');
    return saved ? JSON.parse(saved) : null;
  });

  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [history, setHistory] = useState<ChatMessage[]>(() => {
    const saved = localStorage.getItem('social_gemini_history');
    return saved ? JSON.parse(saved) : [];
  });
  const [transcription, setTranscription] = useState<string>('');
  const [rmsInput, setRmsInput] = useState(0);
  const [rmsOutput, setRmsOutput] = useState(0);

  // Buffer refs
  const currentTurnRef = useRef<{ user: string; model: string }>({ user: '', model: '' });
  const reconnectAttemptsRef = useRef(0);
  const lastSignalTimeRef = useRef(Date.now());

  // --- Audio Pipeline Refs ---
  const inputAudioCtxRef = useRef<AudioContext | null>(null);
  const outputAudioCtxRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  // Sync history
  useEffect(() => {
    localStorage.setItem('social_gemini_history', JSON.stringify(history));
  }, [history]);

  // Initial check for API Key environment
  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio?.hasSelectedApiKey) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(selected);
      } else {
        setHasApiKey(!!process.env.API_KEY);
      }
    };
    checkKey();
    if (!userProfile) setIsProfileModalOpen(true);

    const interval = setInterval(() => {
      if (status === ConnectionStatus.CONNECTED && Date.now() - lastSignalTimeRef.current > 10000) {
        setIsWeakSignal(true);
      } else {
        setIsWeakSignal(false);
      }
    }, 3000);
    return () => clearInterval(interval);
  }, [userProfile, status]);

  const handleOpenSelectKey = async () => {
    if (window.aistudio?.openSelectKey) {
      await window.aistudio.openSelectKey();
      setHasApiKey(true);
      setErrorMessage(null);
      // Instructions: Proceed immediately after trigger
    }
  };

  const stopAllAudio = useCallback(() => {
    sourcesRef.current.forEach(source => {
      try { source.stop(); } catch (e) {}
    });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
    setRmsOutput(0);
    setRmsInput(0);

    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    sessionRef.current = null;
  }, []);

  const connect = async (isReconnecting = false) => {
    if (status === ConnectionStatus.CONNECTING && !isReconnecting) return;

    // Refresh API Key selection if needed
    if (window.aistudio?.hasSelectedApiKey) {
      const selected = await window.aistudio.hasSelectedApiKey();
      if (!selected) {
        await handleOpenSelectKey();
      }
    }

    if (!userProfile) {
      setIsProfileModalOpen(true);
      return;
    }

    try {
      setErrorMessage(null);
      setStatus(isReconnecting ? ConnectionStatus.RECONNECTING : ConnectionStatus.CONNECTING);

      // Initialize Contexts on user interaction
      if (!inputAudioCtxRef.current || inputAudioCtxRef.current.state === 'closed') {
        inputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: INPUT_SAMPLE_RATE });
      }
      if (!outputAudioCtxRef.current || outputAudioCtxRef.current.state === 'closed') {
        outputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: OUTPUT_SAMPLE_RATE });
      }

      const input = inputAudioCtxRef.current;
      const output = outputAudioCtxRef.current;

      if (input.state === 'suspended') await input.resume();
      if (output.state === 'suspended') await output.resume();

      // ALWAYS create a new instance with latest key
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const systemInstruction = `
        You are a warm, patient AI companion named Zephyr. 
        User's Name: ${userProfile.name}. 
        User's Context: On a farm with poor cell bandwidth.

        Behavior:
        - Natural, social voice conversation.
        - Be patient with signal lags. If you hear a gap, wait.
        - Concise responses (1-2 sentences) to save bandwidth.
        - Warm, Reciprocal, Social.
      `;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
          },
          systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setStatus(ConnectionStatus.CONNECTED);
            reconnectAttemptsRef.current = 0;
            lastSignalTimeRef.current = Date.now();

            const source = input.createMediaStreamSource(stream);
            const processor = input.createScriptProcessor(4096, 1, 1);
            processorRef.current = processor;

            processor.onaudioprocess = (e) => {
              // Ensure we only send if we have a resolved session
              const inputData = e.inputBuffer.getChannelData(0);

              // Local RMS for visualization
              let sum = 0;
              for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
              setRmsInput(Math.sqrt(sum / inputData.length));

              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then((session) => {
                try {
                  session.sendRealtimeInput({ media: pcmBlob });
                } catch (err) {
                  console.warn("Failed to send audio chunk", err);
                }
              });
            };

            source.connect(processor);
            processor.connect(input.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            lastSignalTimeRef.current = Date.now();

            // Handle Audio Playback
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
              const audioBuffer = await decodeAudioData(decode(base64Audio), output, OUTPUT_SAMPLE_RATE, 1);
              const source = output.createBufferSource();
              source.buffer = audioBuffer;

              setRmsOutput(0.8); // Peak visual response

              source.connect(output.destination);
              // Gapless scheduling
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, output.currentTime);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;

              sourcesRef.current.add(source);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setRmsOutput(0);
              };
            }

            // Handle Transcriptions
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              setTranscription(prev => (prev + ' ' + text).trim());
              currentTurnRef.current.user += text;
            }
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              setTranscription(prev => (prev + ' ' + text).trim());
              currentTurnRef.current.model += text;
            }

            // Turn end: save to history
            if (message.serverContent?.turnComplete) {
              if (currentTurnRef.current.user || currentTurnRef.current.model) {
                setHistory(prev => [
                  ...prev,
                  { role: 'user', text: currentTurnRef.current.user || '(Speech)', timestamp: Date.now() },
                  { role: 'model', text: currentTurnRef.current.model || '(Speech)', timestamp: Date.now() }
                ].slice(-30));
              }
              currentTurnRef.current = { user: '', model: '' };
              setTranscription('');
            }

            // Handle interruption
            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e: any) => {
            console.error('Session error:', e);
            const msg = (e?.message || e?.toString() || '').toLowerCase();

            if (msg.includes('requested entity was not found') || msg.includes('404')) {
              setErrorMessage("AI Studio Pro project access required. Opening key selection...");
              setHasApiKey(false);
              handleOpenSelectKey(); // Prompt for key immediately
              setStatus(ConnectionStatus.ERROR);
              stopAllAudio();
            } else if (reconnectAttemptsRef.current < MAX_RECONNECT_ATTEMPTS) {
              reconnectAttemptsRef.current++;
              setErrorMessage(`Connection dropped. Retrying link... (${reconnectAttemptsRef.current}/${MAX_RECONNECT_ATTEMPTS})`);
              setTimeout(() => connect(true), 2500);
            } else {
              setErrorMessage("Network signal too weak for Live Audio. Try moving to higher ground.");
              setStatus(ConnectionStatus.ERROR);
              stopAllAudio();
            }
          },
          onclose: (e: any) => {
            console.log('Session closed', e);
            if (status !== ConnectionStatus.ERROR && status !== ConnectionStatus.CONNECTING) {
              if (reconnectAttemptsRef.current < MAX_RECONNECT_ATTEMPTS) {
                reconnectAttemptsRef.current++;
                connect(true);
              } else {
                setStatus(ConnectionStatus.DISCONNECTED);
                stopAllAudio();
              }
            }
          },
        },
      });

      sessionRef.current = await sessionPromise;
    } catch (err: any) {
      console.error('Connect failed:', err);
      setStatus(ConnectionStatus.ERROR);
      setErrorMessage("Could not establish satellite link.");
      stopAllAudio();
    }
  };

  const disconnect = () => {
    reconnectAttemptsRef.current = MAX_RECONNECT_ATTEMPTS; // Kill reconnector
    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch (e) {}
    }
    stopAllAudio();
    setStatus(ConnectionStatus.DISCONNECTED);
  };

  const saveProfile = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const profile: UserProfile = {
      name: formData.get('name') as string,
      relationship: formData.get('relationship') as string,
      interests: (formData.get('interests') as string).split(',').map(s => s.trim()).filter(Boolean),
    };
    setUserProfile(profile);
    localStorage.setItem('social_gemini_profile', JSON.stringify(profile));
    setIsProfileModalOpen(false);
  };

  return (
    <div className="flex flex-col h-screen bg-[#020617] text-slate-100 p-4 md:p-10 font-sans select-none overflow-hidden">
      {/* Network Header */}
      <header className="flex justify-between items-center shrink-0 z-10">
        <div className="flex flex-col">
          <h1 className="text-xl font-black tracking-tighter bg-gradient-to-r from-cyan-400 to-indigo-500 bg-clip-text text-transparent">
            Social Gemini
          </h1>
          <div className="flex items-center space-x-2 mt-1">
            <span className={`w-2 h-2 rounded-full ${
              status === ConnectionStatus.CONNECTED ? 'bg-cyan-400 animate-pulse' : 
              status === ConnectionStatus.RECONNECTING ? 'bg-amber-400 animate-bounce' :
              status === ConnectionStatus.ERROR ? 'bg-red-500' : 'bg-slate-700'
            }`}></span>
            <span className="text-[10px] uppercase tracking-widest font-bold text-slate-500">
              {status}
            </span>
            {isWeakSignal && (
              <span className="text-[9px] font-black text-amber-500 animate-pulse bg-amber-500/10 px-1.5 py-0.5 rounded border border-amber-500/20">
                LOW SIGNAL
              </span>
            )}
          </div>
        </div>

        <div className="flex space-x-2">
           <button 
              onClick={handleOpenSelectKey} 
              className={`px-3 py-1.5 text-[10px] font-bold rounded-xl border transition-all ${
                hasApiKey ? 'bg-slate-900 border-white/10 text-slate-400' : 'bg-cyan-500 border-cyan-400 text-slate-950 animate-pulse'
              }`}
            >
              <i className="fas fa-key mr-2"></i>
              {hasApiKey ? 'AI STUDIO PRO' : 'SET PRO KEY'}
            </button>

          <button onClick={() => setIsHistoryOpen(true)} className="w-10 h-10 rounded-xl bg-slate-900 border border-white/5 flex items-center justify-center text-slate-400 hover:text-cyan-400">
            <i className="fas fa-history text-sm"></i>
          </button>
        </div>
      </header>

      {/* Main Experience */}
      <main className="flex-1 flex flex-col items-center justify-center space-y-12 relative">
        {/* Signal Aura */}
        <div className={`absolute w-[400px] h-[400px] bg-cyan-500/5 rounded-full blur-[100px] transition-opacity duration-1000 ${status === ConnectionStatus.CONNECTED ? 'opacity-100' : 'opacity-0'}`}></div>

        <div className="relative group">
          <div className={`absolute -inset-12 bg-cyan-500/5 rounded-full blur-[60px] transition-all duration-1000 ${status === ConnectionStatus.CONNECTED ? 'scale-150 opacity-100' : 'scale-0 opacity-0'}`}></div>

          <button 
            onClick={status === ConnectionStatus.CONNECTED || status === ConnectionStatus.RECONNECTING ? disconnect : () => connect()}
            disabled={status === ConnectionStatus.CONNECTING}
            className={`relative w-48 h-48 rounded-[3.5rem] flex flex-col items-center justify-center border transition-all duration-700 shadow-3xl ${
              status === ConnectionStatus.CONNECTED 
                ? 'border-cyan-400/30 bg-slate-900/40 backdrop-blur-2xl rotate-3' 
                : status === ConnectionStatus.ERROR
                ? 'border-red-500/20 bg-slate-950'
                : 'border-white/10 bg-slate-950 hover:border-cyan-500/40'
            }`}
          >
            {status === ConnectionStatus.CONNECTING || status === ConnectionStatus.RECONNECTING ? (
              <div className="flex flex-col items-center space-y-3">
                <i className="fas fa-satellite fa-spin text-3xl text-cyan-400"></i>
                <span className="text-[9px] font-black text-cyan-400/60 tracking-widest uppercase">Linking...</span>
              </div>
            ) : status === ConnectionStatus.CONNECTED ? (
              <div className="flex flex-col items-center space-y-2 -rotate-3">
                 <div className="w-20 h-20 bg-cyan-500/20 rounded-full animate-ping absolute"></div>
                 <i className="fas fa-broadcast-tower text-5xl text-cyan-400"></i>
              </div>
            ) : (
              <i className="fas fa-microphone text-slate-800 text-5xl group-hover:text-cyan-400 transition-colors"></i>
            )}
          </button>
        </div>

        <div className="w-full max-w-sm space-y-6 text-center px-4">
          <div className="h-10 overflow-hidden">
            <Waveform isActive={status === ConnectionStatus.CONNECTED} color="#22d3ee" amplitude={Math.max(rmsInput, rmsOutput)} />
          </div>

          <div className="min-h-[60px] flex flex-col items-center justify-center px-6">
            {errorMessage ? (
              <div className="animate-in fade-in zoom-in duration-300">
                 <p className="text-red-400 text-[11px] font-bold uppercase tracking-wider bg-red-500/10 px-4 py-2 rounded-full border border-red-500/20">
                  {errorMessage}
                </p>
                <a 
                  href="https://ai.google.dev/gemini-api/docs/billing" 
                  target="_blank" 
                  rel="noopener noreferrer"
                  className="mt-3 block text-[10px] text-slate-500 underline hover:text-cyan-400"
                >
                  Check AI Studio Billing & Quota
                </a>
              </div>
            ) : (
              <p className="text-slate-500 text-sm font-medium italic leading-relaxed">
                {transcription || (status === ConnectionStatus.CONNECTED ? "Listening on the farm..." : status === ConnectionStatus.RECONNECTING ? "Re-establishing link..." : "Ready to chat") }
              </p>
            )}
          </div>
        </div>
      </main>

      {/* Footer Call Controls */}
      <footer className="shrink-0 flex flex-col items-center pb-12 space-y-4">
        <button 
          onClick={status === ConnectionStatus.CONNECTED || status === ConnectionStatus.RECONNECTING ? disconnect : () => connect()}
          className={`flex items-center space-x-4 px-16 py-6 rounded-[2.5rem] font-black text-xs tracking-[0.2em] uppercase shadow-2xl active:scale-95 transition-all duration-500 ${
            status === ConnectionStatus.CONNECTED || status === ConnectionStatus.RECONNECTING
              ? 'bg-red-500/10 border border-red-500/30 text-red-500'
              : 'bg-gradient-to-br from-cyan-500 to-indigo-600 text-white shadow-cyan-900/40'
          }`}
        >
          <i className={status === ConnectionStatus.CONNECTED ? 'fas fa-phone-slash' : 'fas fa-phone'}></i>
          <span>{status === ConnectionStatus.CONNECTED ? 'End Session' : 'Call Social AI'}</span>
        </button>

        {!hasApiKey && (
          <p className="text-[9px] text-slate-600 font-bold uppercase tracking-widest text-center px-10 leading-loose">
            AI Studio Pro key required for stable Live Audio. <br/>
            <a href="https://ai.google.dev/gemini-api/docs/billing" className="text-cyan-600 underline">Enable billing</a> in your project first.
          </p>
        )}
      </footer>

      {/* Profile Setup Modal */}
      {isProfileModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-[#020617]/95 backdrop-blur-xl">
          <div className="w-full max-w-sm bg-slate-900/50 border border-white/5 rounded-[3rem] p-10 shadow-3xl">
            <h2 className="text-2xl font-black mb-1 tracking-tighter">Your Profile</h2>
            <p className="text-slate-500 text-[10px] mb-8 font-bold uppercase tracking-widest leading-relaxed">Persists even if signal drops</p>
            <form onSubmit={saveProfile} className="space-y-6">
              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1">Name</label>
                <input required name="name" defaultValue={userProfile?.name} className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-4 focus:border-cyan-500 outline-none transition-all text-sm" placeholder="e.g. Farmer Sam" />
              </div>
              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1">Interests</label>
                <input name="interests" defaultValue={userProfile?.interests.join(', ')} className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-4 focus:border-cyan-500 outline-none transition-all text-sm" placeholder="e.g. Livestock, Tech, Weather" />
              </div>
              <button type="submit" className="w-full bg-cyan-500 text-slate-950 font-black py-5 rounded-[2rem] transition-all active:scale-95 shadow-xl hover:bg-cyan-400">
                SAVE & START
              </button>
            </form>
          </div>
        </div>
      )}

      {/* History Drawer */}
      {isHistoryOpen && (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/80 backdrop-blur-sm">
          <div className="w-full max-w-2xl h-[75vh] bg-[#0f172a] border-t border-white/10 rounded-t-[4rem] p-10 shadow-3xl flex flex-col animate-in slide-in-from-bottom duration-500">
            <div className="flex justify-between items-center mb-8">
              <div className="flex flex-col">
                <h2 className="text-2xl font-black tracking-tighter">Call History</h2>
                <span className="text-[9px] font-black text-slate-500 uppercase tracking-[0.2em] mt-1">Local Memory Only</span>
              </div>
              <button onClick={() => setIsHistoryOpen(false)} className="w-12 h-12 rounded-2xl bg-slate-800/50 flex items-center justify-center text-slate-400 hover:text-white transition-colors">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <div className="flex-1 overflow-y-auto space-y-6 pb-10 scrollbar-hide">
              {history.map((msg, idx) => (
                <div key={idx} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                  <div className={`max-w-[85%] px-6 py-4 rounded-[2rem] text-sm font-medium ${msg.role === 'user' ? 'bg-cyan-500 text-slate-950 rounded-tr-none shadow-lg' : 'bg-slate-800/50 text-slate-200 rounded-tl-none border border-white/5 shadow-md'}`}>
                    {msg.text}
                  </div>
                  <span className="text-[8px] font-black text-slate-600 mt-2 px-2 uppercase tracking-widest">
                    {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </span>
                </div>
              ))}
              {history.length === 0 && (
                <div className="flex flex-col items-center justify-center h-full text-slate-700 space-y-4">
                   <i className="fas fa-microchip text-4xl opacity-10"></i>
                   <p className="text-[10px] font-black tracking-[0.3em] uppercase opacity-40">No Logged Speech</p>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function encode(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  // Ensure we handle the buffer precisely to avoid misalignment
  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, data.byteLength / 2);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function createPcmBlob(data: Float32Array): { data: string; mimeType: string } {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    // Standard clamping for 16-bit PCM
    const s = Math.max(-1, Math.min(1, data[i]));
    int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
  }
  return {
    data: encode(new Uint8Array(int16.buffer, int16.byteOffset, int16.byteLength)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { decode, decodeAudioData, createPcmBlob } from './audioUtils';
import { UserProfile, ChatMessage, ConnectionStatus } from './types';
import Waveform from './components/Waveform';

const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;
const MAX_RECONNECT_ATTEMPTS = 5;

const App: React.FC = () => {
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [isWeakSignal, setIsWeakSignal] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('social_gemini_profile');
    return saved ? JSON.parse(saved) : null;
  });

  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [history, setHistory] = useState<ChatMessage[]>(() => {
    const saved = localStorage.getItem('social_gemini_history');
    return saved ? JSON.parse(saved) : [];
  });
  const [transcription, setTranscription] = useState<string>('');
  const [rmsInput, setRmsInput] = useState(0);
  const [rmsOutput, setRmsOutput] = useState(0);

  const userInputBufferRef = useRef('');
  const modelOutputBufferRef = useRef('');
  const reconnectAttemptsRef = useRef(0);
  const lastSignalTimeRef = useRef(Date.now());

  const inputAudioCtxRef = useRef<AudioContext | null>(null);
  const outputAudioCtxRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    localStorage.setItem('social_gemini_history', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio?.hasSelectedApiKey) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(selected);
      } else {
        setHasApiKey(!!process.env.API_KEY);
      }
    };
    checkKey();
    if (!userProfile) setIsProfileModalOpen(true);

    const interval = setInterval(() => {
      if (status === ConnectionStatus.CONNECTED && Date.now() - lastSignalTimeRef.current > 12000) {
        setIsWeakSignal(true);
      } else {
        setIsWeakSignal(false);
      }
    }, 4000);
    return () => clearInterval(interval);
  }, [userProfile, status]);

  const handleOpenSelectKey = async () => {
    if (window.aistudio?.openSelectKey) {
      await window.aistudio.openSelectKey();
      setHasApiKey(true);
    }
  };

  const stopAllAudio = useCallback(() => {
    sourcesRef.current.forEach(source => { try { source.stop(); } catch (e) {} });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
    setRmsOutput(0);
    setRmsInput(0);

    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    sessionRef.current = null;
  }, []);

  const connect = async (isReconnecting = false) => {
    if (status === ConnectionStatus.CONNECTING && !isReconnecting) return;

    if (window.aistudio?.hasSelectedApiKey) {
      const selected = await window.aistudio.hasSelectedApiKey();
      if (!selected) return handleOpenSelectKey();
    }

    try {
      setErrorMessage(null);
      setStatus(isReconnecting ? ConnectionStatus.RECONNECTING : ConnectionStatus.CONNECTING);

      if (!inputAudioCtxRef.current || inputAudioCtxRef.current.state === 'closed') {
        inputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: INPUT_SAMPLE_RATE });
      }
      if (!outputAudioCtxRef.current || outputAudioCtxRef.current.state === 'closed') {
        outputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: OUTPUT_SAMPLE_RATE });
      }

      const input = inputAudioCtxRef.current;
      const output = outputAudioCtxRef.current;

      await input.resume();
      await output.resume();

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const systemInstruction = `
        You are Zephyr, a warm AI farm companion. 
        User: ${userProfile?.name}. Environment: Spotty cell service.
        Behavior: Concise (1-2 sentences), patient, supportive. 
        Focus on reciprocal social conversation.
      `;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
          },
          systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setStatus(ConnectionStatus.CONNECTED);
            reconnectAttemptsRef.current = 0;
            lastSignalTimeRef.current = Date.now();

            const source = input.createMediaStreamSource(stream);
            const processor = input.createScriptProcessor(4096, 1, 1);
            processorRef.current = processor;

            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              let sum = 0;
              for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
              setRmsInput(Math.sqrt(sum / inputData.length));

              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };
            source.connect(processor);
            processor.connect(input.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            lastSignalTimeRef.current = Date.now();

            // Audio Parts
            const parts = message.serverContent?.modelTurn?.parts;
            if (parts) {
              for (const part of parts) {
                if (part.inlineData?.data) {
                  const audioBuffer = await decodeAudioData(decode(part.inlineData.data), output, OUTPUT_SAMPLE_RATE, 1);
                  const source = output.createBufferSource();
                  source.buffer = audioBuffer;
                  setRmsOutput(0.8);
                  source.connect(output.destination);
                  nextStartTimeRef.current = Math.max(nextStartTimeRef.current, output.currentTime);
                  source.start(nextStartTimeRef.current);
                  nextStartTimeRef.current += audioBuffer.duration;
                  sourcesRef.current.add(source);
                  source.onended = () => {
                    sourcesRef.current.delete(source);
                    if (sourcesRef.current.size === 0) setRmsOutput(0);
                  };
                }
              }
            }

            // Transcriptions
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              userInputBufferRef.current += text;
              setTranscription(prev => (prev + ' ' + text).trim());
            }
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              modelOutputBufferRef.current += text;
              setTranscription(prev => (prev + ' ' + text).trim());
            }

            if (message.serverContent?.turnComplete) {
              const userTxt = userInputBufferRef.current.trim();
              const modelTxt = modelOutputBufferRef.current.trim();
              if (userTxt || modelTxt) {
                setHistory(prev => [
                  ...prev,
                  { role: 'user', text: userTxt || '(Spoke)', timestamp: Date.now() },
                  { role: 'model', text: modelTxt || '(Spoke)', timestamp: Date.now() }
                ].slice(-50));
              }
              userInputBufferRef.current = '';
              modelOutputBufferRef.current = '';
              setTranscription('');
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e: any) => {
            console.error('Session Error:', e);
            const msg = (e?.message || e?.toString() || '').toLowerCase();
            if (msg.includes('404') || msg.includes('not found')) {
              setErrorMessage("AI Studio Pro project required.");
              setStatus(ConnectionStatus.ERROR);
              handleOpenSelectKey();
              stopAllAudio();
            } else if (reconnectAttemptsRef.current < MAX_RECONNECT_ATTEMPTS) {
              reconnectAttemptsRef.current++;
              setErrorMessage(`Signal lost. Reconnecting... (${reconnectAttemptsRef.current}/${MAX_RECONNECT_ATTEMPTS})`);
              setTimeout(() => connect(true), 2500);
            } else {
              setErrorMessage("Link failed. Check farm reception.");
              setStatus(ConnectionStatus.ERROR);
              stopAllAudio();
            }
          },
          onclose: () => {
            if (status !== ConnectionStatus.ERROR && status !== ConnectionStatus.CONNECTING) {
              if (reconnectAttemptsRef.current < MAX_RECONNECT_ATTEMPTS) {
                reconnectAttemptsRef.current++;
                connect(true);
              } else {
                setStatus(ConnectionStatus.DISCONNECTED);
                stopAllAudio();
              }
            }
          },
        },
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error('Connection failed:', err);
      setStatus(ConnectionStatus.ERROR);
      stopAllAudio();
    }
  };

  const disconnect = () => {
    reconnectAttemptsRef.current = MAX_RECONNECT_ATTEMPTS;
    if (sessionRef.current) try { sessionRef.current.close(); } catch (e) {}
    stopAllAudio();
    setStatus(ConnectionStatus.DISCONNECTED);
  };

  return (
    <div className="flex flex-col h-screen bg-[#020617] text-slate-100 p-4 md:p-10 font-sans overflow-hidden">
      <header className="flex justify-between items-center z-10">
        <div>
          <h1 className="text-xl font-black tracking-tighter bg-gradient-to-r from-cyan-400 to-indigo-500 bg-clip-text text-transparent">Social Gemini</h1>
          <div className="flex items-center space-x-2 mt-1">
            <span className={`w-2 h-2 rounded-full ${status === ConnectionStatus.CONNECTED ? 'bg-cyan-400 animate-pulse' : 'bg-slate-700'}`}></span>
            <span className="text-[10px] uppercase font-bold text-slate-500">{status}</span>
            {isWeakSignal && <span className="text-[9px] font-black text-amber-500 animate-pulse px-1.5 py-0.5 rounded border border-amber-500/20">LOW SIGNAL</span>}
          </div>
        </div>
        <div className="flex space-x-2">
          <button onClick={handleOpenSelectKey} className={`px-3 py-1.5 text-[10px] font-bold rounded-xl border ${hasApiKey ? 'bg-slate-900 border-white/10 text-slate-400' : 'bg-cyan-500 text-slate-950'}`}>
            <i className="fas fa-key mr-2"></i>{hasApiKey ? 'PRO KEY' : 'SET KEY'}
          </button>
          <button onClick={() => setIsHistoryOpen(true)} className="w-10 h-10 rounded-xl bg-slate-900 border border-white/5 flex items-center justify-center"><i className="fas fa-history"></i></button>
        </div>
      </header>

      <main className="flex-1 flex flex-col items-center justify-center space-y-12">
        <button 
          onClick={status === ConnectionStatus.CONNECTED ? disconnect : () => connect()}
          className={`w-48 h-48 rounded-[3.5rem] flex flex-col items-center justify-center border transition-all duration-700 shadow-3xl ${status === ConnectionStatus.CONNECTED ? 'border-cyan-400/30 bg-slate-900/40 backdrop-blur-2xl rotate-3' : 'border-white/10 bg-slate-950'}`}
        >
          {status === ConnectionStatus.CONNECTED ? <i className="fas fa-broadcast-tower text-5xl text-cyan-400"></i> : <i className="fas fa-microphone text-slate-800 text-5xl"></i>}
        </button>

        <div className="w-full max-w-sm text-center">
          <Waveform isActive={status === ConnectionStatus.CONNECTED} color="#22d3ee" amplitude={Math.max(rmsInput, rmsOutput)} />
          <p className="text-slate-500 text-sm italic mt-6 px-6 min-h-[40px]">{transcription || (status === ConnectionStatus.CONNECTED ? "Listening on the farm..." : "Ready to chat")}</p>
        </div>
      </main>

      <footer className="flex flex-col items-center pb-12 space-y-4">
        <button 
          onClick={status === ConnectionStatus.CONNECTED ? disconnect : () => connect()}
          className={`px-16 py-6 rounded-[2.5rem] font-black text-xs tracking-widest uppercase shadow-2xl transition-all ${status === ConnectionStatus.CONNECTED ? 'bg-red-500/10 text-red-500 border border-red-500/30' : 'bg-gradient-to-br from-cyan-500 to-indigo-600 text-white'}`}
        >
          {status === ConnectionStatus.CONNECTED ? 'End Session' : 'Start Calling'}
        </button>
      </footer>

      {isProfileModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-[#020617]/95 backdrop-blur-xl">
          <form onSubmit={(e) => {
            e.preventDefault();
            const fd = new FormData(e.currentTarget);
            const p = { name: fd.get('name') as string, relationship: '', interests: (fd.get('interests') as string).split(',') };
            setUserProfile(p);
            localStorage.setItem('social_gemini_profile', JSON.stringify(p));
            setIsProfileModalOpen(false);
          }} className="w-full max-w-sm bg-slate-900 border border-white/5 rounded-[3rem] p-10 space-y-6">
            <h2 className="text-2xl font-black">Farm Profile</h2>
            <input required name="name" className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-4 text-sm" placeholder="Your Name" />
            <input name="interests" className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-4 text-sm" placeholder="Interests (farming, etc)" />
            <button className="w-full bg-cyan-500 text-slate-950 font-black py-5 rounded-[2rem]">SAVE & START</button>
          </form>
        </div>
      )}

      {isHistoryOpen && (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/80">
          <div className="w-full max-w-2xl h-[80vh] bg-[#0f172a] rounded-t-[4rem] p-10 flex flex-col">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-2xl font-black">Call Logs</h2>
              <button onClick={() => setIsHistoryOpen(false)} className="text-slate-400 text-2xl">&times;</button>
            </div>
            <div className="flex-1 overflow-y-auto space-y-6 pb-10">
              {history.map((msg, i) => (
                <div key={i} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                  <div className={`max-w-[85%] px-6 py-4 rounded-[2rem] text-sm ${msg.role === 'user' ? 'bg-cyan-500 text-slate-950' : 'bg-slate-800 text-slate-200'}`}>{msg.text}</div>
                  <span className="text-[8px] font-bold text-slate-600 mt-2 px-2 uppercase">{new Date(msg.timestamp).toLocaleTimeString()}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

