        },
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error('Connection failed:', err);
      setStatus(ConnectionStatus.ERROR);
      stopAllAudio();
    }
  };

  const disconnect = () => {
    reconnectAttemptsRef.current = -1; // Flag for manual disconnect
    if (sessionRef.current) try { sessionRef.current.close(); } catch (e) {}
    stopAllAudio();
    setStatus(ConnectionStatus.DISCONNECTED);
    if (currentSessionMessages.length > 0) {
      setShowSummary(true);
    }
  };

  return (
    <div className="flex flex-col h-screen bg-[#000000] text-slate-100 p-4 md:p-10 font-sans overflow-hidden">
      <header className="flex justify-between items-center z-10 shrink-0">
        <div>
          <h1 className="text-xl font-black tracking-tighter bg-gradient-to-r from-orange-400 to-orange-600 bg-clip-text text-transparent">Social Gemini</h1>
          <div className="flex items-center space-x-2 mt-1">
            <span className={`w-2 h-2 rounded-full ${status === ConnectionStatus.CONNECTED ? 'bg-orange-500 animate-pulse' : 'bg-slate-800'}`}></span>
            <span className="text-[10px] uppercase font-bold text-slate-500 tracking-widest">{status}</span>
            {isWeakSignal && <span className="text-[9px] font-black text-orange-500 animate-pulse px-1.5 py-0.5 rounded border border-orange-500/20">LOW SIGNAL</span>}
          </div>
        </div>
        <div className="flex space-x-2">
          <button onClick={handleOpenSelectKey} className={`px-3 py-1.5 text-[10px] font-bold rounded-xl border transition-colors ${hasApiKey ? 'bg-black border-white/10 text-slate-400' : 'bg-orange-500 text-black border-orange-400'}`}>
            <i className="fas fa-key mr-2"></i>{hasApiKey ? 'PRO KEY' : 'SET KEY'}
          </button>
          <button onClick={() => setIsHistoryOpen(true)} className="w-10 h-10 rounded-xl bg-slate-900/50 border border-white/5 flex items-center justify-center text-orange-500 hover:bg-orange-500/10 transition-colors"><i className="fas fa-history"></i></button>
        </div>
      </header>

      <main className="flex-1 flex flex-col items-center justify-center space-y-12 relative">
        {/* Visualizer Aura */}
        <div className={`absolute w-64 h-64 bg-orange-500/5 rounded-full blur-3xl transition-opacity duration-1000 ${status === ConnectionStatus.CONNECTED ? 'opacity-100' : 'opacity-0'}`}></div>

        <button 
          onClick={status === ConnectionStatus.CONNECTED ? disconnect : () => connect()}
          className={`group relative w-48 h-48 rounded-[3.5rem] flex flex-col items-center justify-center border transition-all duration-700 orange-glow ${status === ConnectionStatus.CONNECTED ? 'border-orange-500/40 bg-orange-950/10 rotate-3 scale-105' : 'border-white/5 bg-slate-950 hover:border-orange-500/30'}`}
        >
          {status === ConnectionStatus.CONNECTED ? (
            <div className="flex flex-col items-center space-y-2">
               <i className="fas fa-broadcast-tower text-6xl text-orange-500 pulse-animation"></i>
               <span className="text-[10px] font-black text-orange-500/60 uppercase tracking-widest">Live Link</span>
            </div>
          ) : (
            <i className="fas fa-microphone text-slate-800 text-5xl group-hover:text-orange-500 transition-colors"></i>
          )}
        </button>

        <div className="w-full max-w-sm text-center space-y-4">
          <div className="h-16 flex items-center justify-center">
            <Waveform isActive={status === ConnectionStatus.CONNECTED} color="#f97316" amplitude={Math.max(rmsInput, rmsOutput)} />
          </div>
          <p className="text-slate-400 text-sm italic px-8 min-h-[48px] leading-relaxed">
            {transcription || (status === ConnectionStatus.CONNECTED ? "Listening on the farm..." : "Ready to chat. Tap above to start.")}
          </p>
        </div>
      </main>

      <footer className="flex flex-col items-center pb-12 space-y-4 shrink-0">
        <button 
          onClick={status === ConnectionStatus.CONNECTED ? disconnect : () => connect()}
          className={`group flex items-center space-x-3 px-20 py-6 rounded-[2.5rem] font-black text-xs tracking-[0.2em] uppercase shadow-2xl transition-all active:scale-95 ${status === ConnectionStatus.CONNECTED ? 'bg-red-500/10 text-red-500 border border-red-500/20' : 'bg-gradient-to-br from-orange-500 to-orange-700 text-black shadow-orange-950/20'}`}
        >
          <i className={status === ConnectionStatus.CONNECTED ? 'fas fa-phone-slash' : 'fas fa-phone'}></i>
          <span>{status === ConnectionStatus.CONNECTED ? 'Hang Up' : 'Call Zephyr'}</span>
        </button>
      </footer>

      {/* Profile Setup Modal */}
      {isProfileModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-black/95 backdrop-blur-xl">
          <form onSubmit={(e) => {
            e.preventDefault();
            const fd = new FormData(e.currentTarget);
            const p = { name: fd.get('name') as string, relationship: '', interests: (fd.get('interests') as string).split(',') };
            setUserProfile(p);
            localStorage.setItem('social_gemini_profile', JSON.stringify(p));
            setIsProfileModalOpen(false);
          }} className="w-full max-w-sm bg-slate-900/50 border border-white/5 rounded-[3rem] p-10 space-y-8">
            <div className="text-center">
              <h2 className="text-3xl font-black tracking-tighter">Zephyr Voice</h2>
              <p className="text-orange-500/60 text-[10px] uppercase font-bold tracking-[0.3em] mt-1">Farm AI Configuration</p>
            </div>
            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Your Name</label>
                <input required name="name" className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-4 text-sm focus:border-orange-500/50 outline-none transition-all" placeholder="e.g. Farmer Joe" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Interests</label>
                <input name="interests" className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-4 text-sm focus:border-orange-500/50 outline-none transition-all" placeholder="e.g. crops, machinery, weather" />
              </div>
            </div>
            <button className="w-full bg-orange-500 text-black font-black py-5 rounded-[2rem] hover:bg-orange-400 transition-colors shadow-lg shadow-orange-900/10 uppercase text-xs tracking-widest">Save & Connect</button>
          </form>
        </div>
      )}

      {/* Session Summary Modal */}
      {showSummary && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/90 backdrop-blur-lg animate-in fade-in duration-300">
           <div className="w-full max-w-xl bg-slate-900/80 border border-white/10 rounded-[3rem] p-8 md:p-12 flex flex-col max-h-[85vh] shadow-3xl">
              <div className="flex justify-between items-start mb-6">
                 <div>
                    <h2 className="text-3xl font-black tracking-tighter">Call Summary</h2>
                    <p className="text-orange-500 text-[10px] font-black uppercase tracking-widest mt-1">Transcription Saved</p>
                 </div>
                 <button onClick={() => setShowSummary(false)} className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center text-slate-400 hover:text-white transition-colors">
                    <i className="fas fa-times"></i>
                 </button>
              </div>
              <div className="flex-1 overflow-y-auto space-y-6 pr-2 scrollbar-hide">
                 {currentSessionMessages.map((msg, i) => (
                    <div key={i} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                       <span className="text-[9px] font-black text-slate-600 uppercase tracking-[0.2em] mb-2 px-2">
                          {msg.role === 'user' ? userProfile?.name : 'Zephyr'}
                       </span>
                       <div className={`max-w-[90%] px-6 py-4 rounded-[2rem] text-sm leading-relaxed ${msg.role === 'user' ? 'bg-orange-500 text-black rounded-tr-none' : 'bg-slate-800 text-slate-200 rounded-tl-none border border-white/5'}`}>
                          {msg.text}
                       </div>
                    </div>
                 ))}
                 {currentSessionMessages.length === 0 && (
                    <p className="text-slate-600 italic text-center text-sm py-10">No spoken words were captured in this short session.</p>
                 )}
              </div>
              <button onClick={() => setShowSummary(false)} className="mt-8 w-full bg-white/5 hover:bg-white/10 text-slate-300 font-bold py-4 rounded-2xl transition-all uppercase text-[10px] tracking-[0.3em]">
                 Close Summary
              </button>
           </div>
        </div>
      )}

      {/* History Drawer */}
      {isHistoryOpen && (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/80 backdrop-blur-sm">
          <div className="w-full max-w-2xl h-[80vh] bg-[#0a0a0a] border-t border-white/10 rounded-t-[4rem] p-8 md:p-12 flex flex-col animate-in slide-in-from-bottom duration-500">
            <div className="flex justify-between items-center mb-10">
              <div>
                <h2 className="text-2xl font-black tracking-tighter">Call Logs</h2>
                <p className="text-orange-500 text-[9px] font-black uppercase tracking-[0.2em] mt-1">Previous Conversations</p>
              </div>
              <button onClick={() => setIsHistoryOpen(false)} className="w-12 h-12 rounded-2xl bg-slate-900 border border-white/5 flex items-center justify-center text-slate-400 hover:text-white transition-colors">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <div className="flex-1 overflow-y-auto space-y-6 pb-10 pr-2">
              {history.map((msg, i) => (
                <div key={i} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                  <div className={`max-w-[85%] px-6 py-4 rounded-[2rem] text-sm leading-relaxed ${msg.role === 'user' ? 'bg-orange-500/90 text-black font-medium' : 'bg-slate-900 text-slate-200 border border-white/5'}`}>
                    {msg.text}
                  </div>
                  <span className="text-[8px] font-bold text-slate-600 mt-2 px-3 uppercase tracking-widest">{new Date(msg.timestamp).toLocaleTimeString()}</span>
                </div>
              ))}
              {history.length === 0 && (
                <div className="flex flex-col items-center justify-center h-full text-slate-800 space-y-4">
                   <i className="fas fa-ghost text-5xl opacity-10"></i>
                   <p className="text-[10px] font-black tracking-[0.4em] uppercase opacity-20">No logged history</p>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useEffect, useRef } from 'react';

interface WaveformProps {
  isActive: boolean;
  color: string;
  amplitude?: number;
}

const Waveform: React.FC<WaveformProps> = ({ isActive, color, amplitude = 0 }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationRef = useRef<number>();

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let offset = 0;
    const draw = () => {
      const { width, height } = canvas;
      ctx.clearRect(0, 0, width, height);

      const midY = height / 2;

      if (isActive) {
        ctx.beginPath();
        ctx.strokeStyle = color;
        ctx.lineWidth = 3;
        ctx.lineCap = 'round';

        const segments = 50;
        const segmentWidth = width / segments;

        ctx.moveTo(0, midY);

        for (let i = 0; i <= segments; i++) {
          const x = i * segmentWidth;
          // Dynamically scale based on amplitude
          const variance = amplitude * 40;
          // Add some organic jitter/wave
          const y = midY + Math.sin(i * 0.4 + offset) * variance;
          ctx.lineTo(x, y);
        }

        ctx.stroke();

        // Add a secondary subtle glow wave
        ctx.beginPath();
        ctx.strokeStyle = color + '33'; // 20% opacity
        ctx.lineWidth = 6;
        ctx.moveTo(0, midY);
        for (let i = 0; i <= segments; i++) {
          const x = i * segmentWidth;
          const variance = amplitude * 50;
          const y = midY + Math.sin(i * 0.3 + offset * 0.8) * variance;
          ctx.lineTo(x, y);
        }
        ctx.stroke();

        offset += 0.15;
      } else {
        // Subtle resting line
        ctx.beginPath();
        ctx.strokeStyle = '#1e293b';
        ctx.lineWidth = 1;
        ctx.setLineDash([5, 5]);
        ctx.moveTo(0, midY);
        ctx.lineTo(width, midY);
        ctx.stroke();
        ctx.setLineDash([]);
      }

      animationRef.current = requestAnimationFrame(draw);
    };

    draw();
    return () => {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [isActive, color, amplitude]);

  return (
    <canvas 
      ref={canvasRef} 
      width={400} 
      height={80} 
      className="w-full h-16 rounded-lg pointer-events-none"
    />
  );
};

