import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { decode, decodeAudioData, createPcmBlob } from './audioUtils';
import { UserProfile, ChatMessage, ConnectionStatus } from './types';
import Waveform from './components/Waveform';

const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;
const MAX_RECONNECT_ATTEMPTS = 5;

const App: React.FC = () => {
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [isWeakSignal, setIsWeakSignal] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('social_gemini_profile');
    return saved ? JSON.parse(saved) : null;
  });

  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [showSummary, setShowSummary] = useState(false);
  const [currentSessionMessages, setCurrentSessionMessages] = useState<ChatMessage[]>([]);
  const [history, setHistory] = useState<ChatMessage[]>(() => {
    const saved = localStorage.getItem('social_gemini_history');
    return saved ? JSON.parse(saved) : [];
  });
  const [transcription, setTranscription] = useState<string>('');
  const [rmsInput, setRmsInput] = useState(0);
  const [rmsOutput, setRmsOutput] = useState(0);

  const userInputBufferRef = useRef('');
  const modelOutputBufferRef = useRef('');
  const reconnectAttemptsRef = useRef(0);
  const lastSignalTimeRef = useRef(Date.now());

  const inputAudioCtxRef = useRef<AudioContext | null>(null);
  const outputAudioCtxRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    localStorage.setItem('social_gemini_history', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio?.hasSelectedApiKey) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(selected);
      } else {
        setHasApiKey(!!process.env.API_KEY);
      }
    };
    checkKey();
    if (!userProfile) setIsProfileModalOpen(true);

    const interval = setInterval(() => {
      if (status === ConnectionStatus.CONNECTED && Date.now() - lastSignalTimeRef.current > 12000) {
        setIsWeakSignal(true);
      } else {
        setIsWeakSignal(false);
      }
    }, 4000);
    return () => clearInterval(interval);
  }, [userProfile, status]);

  const handleOpenSelectKey = async () => {
    if (window.aistudio?.openSelectKey) {
      await window.aistudio.openSelectKey();
      setHasApiKey(true);
    }
  };

  const stopAllAudio = useCallback(() => {
    sourcesRef.current.forEach(source => { try { source.stop(); } catch (e) {} });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
    setRmsOutput(0);
    setRmsInput(0);

    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    sessionRef.current = null;
  }, []);

  const connect = async (isReconnecting = false) => {
    if (status === ConnectionStatus.CONNECTING && !isReconnecting) return;

    if (window.aistudio?.hasSelectedApiKey) {
      const selected = await window.aistudio.hasSelectedApiKey();
      if (!selected) return handleOpenSelectKey();
    }

    try {
      setShowSummary(false);
      setCurrentSessionMessages([]);
      setErrorMessage(null);
      setStatus(isReconnecting ? ConnectionStatus.RECONNECTING : ConnectionStatus.CONNECTING);

      if (!inputAudioCtxRef.current || inputAudioCtxRef.current.state === 'closed') {
        inputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: INPUT_SAMPLE_RATE });
      }
      if (!outputAudioCtxRef.current || outputAudioCtxRef.current.state === 'closed') {
        outputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: OUTPUT_SAMPLE_RATE });
      }

      const input = inputAudioCtxRef.current;
      const output = outputAudioCtxRef.current;

      await input.resume();
      await output.resume();

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const memoryContext = `
        User Name: ${userProfile?.name || 'Friend'}.
        Interests: ${userProfile?.interests.join(', ') || 'None'}.
        Pets: ${userProfile?.petNames || 'Not mentioned yet'}.
        Daily Routine: ${userProfile?.dailyRoutine || 'Not mentioned yet'}.
      `;

      const systemInstruction = `
        You are Zephyr, a warm and empathetic AI companion. You have a social, friendly personality.
        You are chatting with ${userProfile?.name || 'the user'}. 

        Important Persistent Context (Remember these!):
        ${memoryContext}

        Behavior Guidelines:
        1. Be concise (1-2 sentences) to accommodate potentially slow network speeds.
        2. Actively reference the user's pets and routine where appropriate to show you remember them.
        3. This is a relaxed social conversation. Be supportive and a good listener.
        4. If the user shares new details about their life, acknowledge them warmly.
      `;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
          },
          systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setStatus(ConnectionStatus.CONNECTED);
            reconnectAttemptsRef.current = 0;
            lastSignalTimeRef.current = Date.now();

            const source = input.createMediaStreamSource(stream);
            const processor = input.createScriptProcessor(4096, 1, 1);
            processorRef.current = processor;

            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              let sum = 0;
              for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
              setRmsInput(Math.sqrt(sum / inputData.length));

              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };
            source.connect(processor);
            processor.connect(input.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            lastSignalTimeRef.current = Date.now();

            // Handle Audio
            const parts = message.serverContent?.modelTurn?.parts;
            if (parts) {
              for (const part of parts) {
                if (part.inlineData?.data) {
                  const audioBuffer = await decodeAudioData(decode(part.inlineData.data), output, OUTPUT_SAMPLE_RATE, 1);
                  const source = output.createBufferSource();
                  source.buffer = audioBuffer;
                  setRmsOutput(0.8);
                  source.connect(output.destination);
                  nextStartTimeRef.current = Math.max(nextStartTimeRef.current, output.currentTime);
                  source.start(nextStartTimeRef.current);
                  nextStartTimeRef.current += audioBuffer.duration;
                  sourcesRef.current.add(source);
                  source.onended = () => {
                    sourcesRef.current.delete(source);
                    if (sourcesRef.current.size === 0) setRmsOutput(0);
                  };
                }
              }
            }

            // Handle Transcriptions
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              userInputBufferRef.current += text;
              setTranscription(prev => (prev + ' ' + text).trim());
            }
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              modelOutputBufferRef.current += text;
              setTranscription(prev => (prev + ' ' + text).trim());
            }

            if (message.serverContent?.turnComplete) {
              const userTxt = userInputBufferRef.current.trim();
              const modelTxt = modelOutputBufferRef.current.trim();
              if (userTxt || modelTxt) {
                const msgs: ChatMessage[] = [
                  { role: 'user', text: userTxt || '(User spoke)', timestamp: Date.now() },
                  { role: 'model', text: modelTxt || '(Zephyr spoke)', timestamp: Date.now() }
                ];
                setHistory(prev => [...prev, ...msgs].slice(-100));
                setCurrentSessionMessages(prev => [...prev, ...msgs]);
              }
              userInputBufferRef.current = '';
              modelOutputBufferRef.current = '';
              setTranscription('');
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e: any) => {
            console.error('Session Error:', e);
            const msg = (e?.message || e?.toString() || '').toLowerCase();
            if (msg.includes('404') || msg.includes('not found')) {
              setErrorMessage("AI Studio Pro project required.");
              setStatus(ConnectionStatus.ERROR);
              handleOpenSelectKey();
              stopAllAudio();
            } else if (reconnectAttemptsRef.current < MAX_RECONNECT_ATTEMPTS) {
              reconnectAttemptsRef.current++;
              setErrorMessage(`Reconnecting... (${reconnectAttemptsRef.current}/${MAX_RECONNECT_ATTEMPTS})`);
              setTimeout(() => connect(true), 2500);
            } else {
              setErrorMessage("Connection failed.");
              setStatus(ConnectionStatus.ERROR);
              stopAllAudio();
            }
          },
          onclose: () => {
            if (status !== ConnectionStatus.ERROR && status !== ConnectionStatus.CONNECTING) {
              if (reconnectAttemptsRef.current < MAX_RECONNECT_ATTEMPTS && reconnectAttemptsRef.current > 0) {
                reconnectAttemptsRef.current++;
                connect(true);
              } else {
                setStatus(ConnectionStatus.DISCONNECTED);
                stopAllAudio();
                if (currentSessionMessages.length > 0) setShowSummary(true);
              }
            }
          },
        },
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error('Connection failed:', err);
      setStatus(ConnectionStatus.ERROR);
      stopAllAudio();
    }
  };

  const disconnect = () => {
    reconnectAttemptsRef.current = -1; 
    if (sessionRef.current) try { sessionRef.current.close(); } catch (e) {}
    stopAllAudio();
    setStatus(ConnectionStatus.DISCONNECTED);
    if (currentSessionMessages.length > 0) setShowSummary(true);
  };

  return (
    <div className="flex flex-col h-screen bg-black text-slate-100 p-4 md:p-10 font-sans overflow-hidden">
      <header className="flex justify-between items-center z-10 shrink-0">
        <div>
          <h1 className="text-xl font-black tracking-tighter bg-gradient-to-r from-orange-400 to-orange-600 bg-clip-text text-transparent">Social Gemini</h1>
          <div className="flex items-center space-x-2 mt-1">
            <span className={`w-2 h-2 rounded-full ${status === ConnectionStatus.CONNECTED ? 'bg-orange-500 animate-pulse' : 'bg-slate-800'}`}></span>
            <span className="text-[10px] uppercase font-bold text-slate-500 tracking-widest">{status}</span>
            {isWeakSignal && <span className="text-[9px] font-black text-orange-500 animate-pulse px-1.5 py-0.5 rounded border border-orange-500/20 ml-2">LOW SIGNAL</span>}
          </div>
        </div>
        <div className="flex space-x-2">
          <button onClick={() => setIsProfileModalOpen(true)} className="w-10 h-10 rounded-xl bg-slate-900 border border-white/5 flex items-center justify-center text-slate-400 hover:text-orange-500 transition-colors">
            <i className="fas fa-user-circle"></i>
          </button>
          <button onClick={() => setIsHistoryOpen(true)} className="w-10 h-10 rounded-xl bg-slate-900 border border-white/5 flex items-center justify-center text-orange-500 hover:bg-orange-500/10 transition-colors">
            <i className="fas fa-history"></i>
          </button>
        </div>
      </header>

      <main className="flex-1 flex flex-col items-center justify-center space-y-12 relative">
        <div className={`absolute w-64 h-64 bg-orange-500/5 rounded-full blur-3xl transition-opacity duration-1000 ${status === ConnectionStatus.CONNECTED ? 'opacity-100' : 'opacity-0'}`}></div>

        <button 
          onClick={status === ConnectionStatus.CONNECTED ? disconnect : () => connect()}
          className={`group relative w-48 h-48 rounded-[3.5rem] flex flex-col items-center justify-center border transition-all duration-700 orange-glow ${status === ConnectionStatus.CONNECTED ? 'border-orange-500/40 bg-orange-950/10 rotate-3 scale-105' : 'border-white/5 bg-slate-950 hover:border-orange-500/30'}`}
        >
          {status === ConnectionStatus.CONNECTED ? (
            <div className="flex flex-col items-center space-y-2">
               <i className="fas fa-broadcast-tower text-6xl text-orange-500 pulse-animation"></i>
            </div>
          ) : (
            <i className="fas fa-microphone text-slate-800 text-5xl group-hover:text-orange-500 transition-colors"></i>
          )}
        </button>

        <div className="w-full max-w-sm text-center space-y-6">
          <div className="h-16 flex items-center justify-center">
            <Waveform isActive={status === ConnectionStatus.CONNECTED} color="#f97316" amplitude={Math.max(rmsInput, rmsOutput)} />
          </div>
          <p className="text-slate-400 text-sm italic px-8 min-h-[48px] leading-relaxed">
            {transcription || (status === ConnectionStatus.CONNECTED ? "Listening..." : "Tap to start conversation.")}
          </p>
        </div>
      </main>

      <footer className="flex flex-col items-center pb-12 shrink-0">
        <button 
          onClick={status === ConnectionStatus.CONNECTED ? disconnect : () => connect()}
          className={`group flex items-center space-x-3 px-20 py-6 rounded-[2.5rem] font-black text-xs tracking-widest uppercase shadow-2xl transition-all active:scale-95 ${status === ConnectionStatus.CONNECTED ? 'bg-red-500/10 text-red-500 border border-red-500/20' : 'bg-gradient-to-br from-orange-500 to-orange-700 text-black shadow-orange-900/40'}`}
        >
          <i className={status === ConnectionStatus.CONNECTED ? 'fas fa-phone-slash' : 'fas fa-phone'}></i>
          <span>{status === ConnectionStatus.CONNECTED ? 'Hang Up' : 'Start Call'}</span>
        </button>
      </footer>

      {/* Profile Modal */}
      {isProfileModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-black/95 backdrop-blur-xl">
          <form onSubmit={(e) => {
            e.preventDefault();
            const fd = new FormData(e.currentTarget);
            const p = { 
              name: fd.get('name') as string, 
              relationship: '', 
              interests: (fd.get('interests') as string).split(','),
              petNames: fd.get('petNames') as string,
              dailyRoutine: fd.get('dailyRoutine') as string
            };
            setUserProfile(p);
            localStorage.setItem('social_gemini_profile', JSON.stringify(p));
            setIsProfileModalOpen(false);
          }} className="w-full max-w-md bg-slate-900/50 border border-white/5 rounded-[3rem] p-10 space-y-6 max-h-[90vh] overflow-y-auto scrollbar-hide">
            <div className="text-center">
              <h2 className="text-2xl font-black tracking-tight">Your Profile</h2>
              <p className="text-orange-500/60 text-[10px] uppercase font-bold tracking-widest mt-1">AI Context Memory</p>
            </div>
            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Name</label>
                <input required name="name" defaultValue={userProfile?.name} className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-3 text-sm focus:border-orange-500/50 outline-none" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Interests (comma separated)</label>
                <input name="interests" defaultValue={userProfile?.interests.join(',')} className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-3 text-sm focus:border-orange-500/50 outline-none" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Pet Names</label>
                <textarea name="petNames" defaultValue={userProfile?.petNames} rows={2} className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-3 text-sm focus:border-orange-500/50 outline-none" placeholder="e.g. Buster the dog, Mittens the cat" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Daily Routine</label>
                <textarea name="dailyRoutine" defaultValue={userProfile?.dailyRoutine} rows={3} className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-3 text-sm focus:border-orange-500/50 outline-none" placeholder="e.g. Work 9-5, gym in the morning, reads before bed" />
              </div>
            </div>
            <button className="w-full bg-orange-500 text-black font-black py-4 rounded-[2rem] hover:bg-orange-400 transition-colors uppercase text-xs tracking-widest">Update Memory</button>
            <button type="button" onClick={() => setIsProfileModalOpen(false)} className="w-full text-slate-500 font-bold text-[10px] uppercase tracking-widest py-2">Cancel</button>
          </form>
        </div>
      )}

      {/* Summary Modal */}
      {showSummary && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/90 backdrop-blur-lg">
           <div className="w-full max-w-xl bg-slate-900/80 border border-white/10 rounded-[3rem] p-8 md:p-12 flex flex-col max-h-[85vh]">
              <div className="flex justify-between items-start mb-6">
                 <div>
                    <h2 className="text-2xl font-black tracking-tight">Call Summary</h2>
                    <p className="text-orange-500 text-[10px] font-black uppercase tracking-widest mt-1">Full Session Transcript</p>
                 </div>
                 <button onClick={() => setShowSummary(false)} className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center text-slate-400 hover:text-white transition-colors">
                    <i className="fas fa-times"></i>
                 </button>
              </div>
              <div className="flex-1 overflow-y-auto space-y-6 pr-2 scrollbar-hide">
                 {currentSessionMessages.map((msg, i) => (
                    <div key={i} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                       <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest mb-1 px-2">
                          {msg.role === 'user' ? userProfile?.name || 'You' : 'Zephyr'}
                       </span>
                       <div className={`max-w-[90%] px-5 py-3 rounded-[1.5rem] text-sm leading-relaxed ${msg.role === 'user' ? 'bg-orange-500 text-black rounded-tr-none' : 'bg-slate-800 text-slate-200 rounded-tl-none'}`}>
                          {msg.text}
                       </div>
                    </div>
                 ))}
              </div>
              <button onClick={() => setShowSummary(false)} className="mt-8 w-full bg-orange-500 text-black font-black py-4 rounded-2xl uppercase text-[10px] tracking-widest shadow-xl">
                 Close Transcript
              </button>
           </div>
        </div>
      )}

      {/* History Drawer */}
      {isHistoryOpen && (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/80 backdrop-blur-sm">
          <div className="w-full max-w-2xl h-[80vh] bg-[#0a0a0a] border-t border-white/10 rounded-t-[4rem] p-8 md:p-12 flex flex-col">
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-2xl font-black tracking-tighter">Call History</h2>
              <button onClick={() => setIsHistoryOpen(false)} className="w-12 h-12 rounded-2xl bg-slate-900 border border-white/5 flex items-center justify-center text-slate-400 hover:text-white transition-colors">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <div className="flex-1 overflow-y-auto space-y-8 pb-10 pr-2 scrollbar-hide">
              {history.map((msg, i) => (
                <div key={i} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                  <div className={`max-w-[85%] px-6 py-4 rounded-[2rem] text-sm leading-relaxed ${msg.role === 'user' ? 'bg-orange-500/90 text-black font-medium' : 'bg-slate-900 text-slate-200 border border-white/5'}`}>
                    {msg.text}
                  </div>
                  <span className="text-[8px] font-bold text-slate-600 mt-2 px-3 uppercase tracking-widest">{new Date(msg.timestamp).toLocaleString()}</span>
                </div>
              ))}
              {history.length === 0 && <p className="text-center text-slate-600 italic">No history yet.</p>}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { decode, decodeAudioData, createPcmBlob } from './audioUtils';
import { UserProfile, ChatMessage, ConnectionStatus } from './types';
import Waveform from './components/Waveform';

const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;
const MAX_RECONNECT_ATTEMPTS = 5;

const App: React.FC = () => {
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [isWeakSignal, setIsWeakSignal] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('social_gemini_profile');
    return saved ? JSON.parse(saved) : null;
  });

  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [showSummary, setShowSummary] = useState(false);
  const [currentSessionMessages, setCurrentSessionMessages] = useState<ChatMessage[]>([]);
  const [history, setHistory] = useState<ChatMessage[]>(() => {
    const saved = localStorage.getItem('social_gemini_history');
    return saved ? JSON.parse(saved) : [];
  });
  const [transcription, setTranscription] = useState<string>('');
  const [rmsInput, setRmsInput] = useState(0);
  const [rmsOutput, setRmsOutput] = useState(0);
  const [syncCode, setSyncCode] = useState('');

  const userInputBufferRef = useRef('');
  const modelOutputBufferRef = useRef('');
  const reconnectAttemptsRef = useRef(0);
  const lastSignalTimeRef = useRef(Date.now());

  const inputAudioCtxRef = useRef<AudioContext | null>(null);
  const outputAudioCtxRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    localStorage.setItem('social_gemini_history', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio?.hasSelectedApiKey) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(selected);
      } else {
        setHasApiKey(!!process.env.API_KEY);
      }
    };
    checkKey();
    if (!userProfile) setIsProfileModalOpen(true);

    const interval = setInterval(() => {
      if (status === ConnectionStatus.CONNECTED && Date.now() - lastSignalTimeRef.current > 12000) {
        setIsWeakSignal(true);
      } else {
        setIsWeakSignal(false);
      }
    }, 4000);
    return () => clearInterval(interval);
  }, [userProfile, status]);

  const handleOpenSelectKey = async () => {
    if (window.aistudio?.openSelectKey) {
      await window.aistudio.openSelectKey();
      setHasApiKey(true);
    }
  };

  const stopAllAudio = useCallback(() => {
    sourcesRef.current.forEach(source => { try { source.stop(); } catch (e) {} });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
    setRmsOutput(0);
    setRmsInput(0);

    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    sessionRef.current = null;
  }, []);

  const connect = async (isReconnecting = false) => {
    if (status === ConnectionStatus.CONNECTING && !isReconnecting) return;

    if (window.aistudio?.hasSelectedApiKey) {
      const selected = await window.aistudio.hasSelectedApiKey();
      if (!selected) return handleOpenSelectKey();
    }

    try {
      setShowSummary(false);
      setCurrentSessionMessages([]);
      setErrorMessage(null);
      setStatus(isReconnecting ? ConnectionStatus.RECONNECTING : ConnectionStatus.CONNECTING);

      if (!inputAudioCtxRef.current || inputAudioCtxRef.current.state === 'closed') {
        inputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: INPUT_SAMPLE_RATE });
      }
      if (!outputAudioCtxRef.current || outputAudioCtxRef.current.state === 'closed') {
        outputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: OUTPUT_SAMPLE_RATE });
      }

      const input = inputAudioCtxRef.current;
      const output = outputAudioCtxRef.current;

      await input.resume();
      await output.resume();

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const memoryContext = `
        User Name: ${userProfile?.name || 'Friend'}.
        Interests: ${userProfile?.interests.join(', ') || 'None'}.
        Pets: ${userProfile?.petNames || 'Not mentioned yet'}.
        Daily Routine: ${userProfile?.dailyRoutine || 'Not mentioned yet'}.
      `;

      const systemInstruction = `
        You are Zephyr, a warm and empathetic AI companion. You have a social, friendly personality.
        You are chatting with ${userProfile?.name || 'the user'}. 

        Important Persistent Context (Remember these!):
        ${memoryContext}

        Behavior Guidelines:
        1. Be concise (1-2 sentences) to accommodate potentially slow network speeds.
        2. Actively reference the user's pets and routine where appropriate to show you remember them.
        3. This is a relaxed social conversation. Be supportive and a good listener.
        4. If the user shares new details about their life, acknowledge them warmly.
      `;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
          },
          systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setStatus(ConnectionStatus.CONNECTED);
            reconnectAttemptsRef.current = 0;
            lastSignalTimeRef.current = Date.now();

            const source = input.createMediaStreamSource(stream);
            const processor = input.createScriptProcessor(4096, 1, 1);
            processorRef.current = processor;

            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              let sum = 0;
              for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
              setRmsInput(Math.sqrt(sum / inputData.length));

              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };
            source.connect(processor);
            processor.connect(input.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            lastSignalTimeRef.current = Date.now();

            // Handle Audio
            const parts = message.serverContent?.modelTurn?.parts;
            if (parts) {
              for (const part of parts) {
                if (part.inlineData?.data) {
                  const audioBuffer = await decodeAudioData(decode(part.inlineData.data), output, OUTPUT_SAMPLE_RATE, 1);
                  const source = output.createBufferSource();
                  source.buffer = audioBuffer;
                  setRmsOutput(0.8);
                  source.connect(output.destination);
                  nextStartTimeRef.current = Math.max(nextStartTimeRef.current, output.currentTime);
                  source.start(nextStartTimeRef.current);
                  nextStartTimeRef.current += audioBuffer.duration;
                  sourcesRef.current.add(source);
                  source.onended = () => {
                    sourcesRef.current.delete(source);
                    if (sourcesRef.current.size === 0) setRmsOutput(0);
                  };
                }
              }
            }

            // Handle Transcriptions
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              userInputBufferRef.current += text;
              setTranscription(prev => (prev + ' ' + text).trim());
            }
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              modelOutputBufferRef.current += text;
              setTranscription(prev => (prev + ' ' + text).trim());
            }

            if (message.serverContent?.turnComplete) {
              const userTxt = userInputBufferRef.current.trim();
              const modelTxt = modelOutputBufferRef.current.trim();
              if (userTxt || modelTxt) {
                const msgs: ChatMessage[] = [
                  { role: 'user', text: userTxt || '(User spoke)', timestamp: Date.now() },
                  { role: 'model', text: modelTxt || '(Zephyr spoke)', timestamp: Date.now() }
                ];
                setHistory(prev => [...prev, ...msgs].slice(-100));
                setCurrentSessionMessages(prev => [...prev, ...msgs]);
              }
              userInputBufferRef.current = '';
              modelOutputBufferRef.current = '';
              setTranscription('');
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e: any) => {
            console.error('Session Error:', e);
            const msg = (e?.message || e?.toString() || '').toLowerCase();
            if (msg.includes('404') || msg.includes('not found')) {
              setErrorMessage("AI Studio Pro project required.");
              setStatus(ConnectionStatus.ERROR);
              handleOpenSelectKey();
              stopAllAudio();
            } else if (reconnectAttemptsRef.current < MAX_RECONNECT_ATTEMPTS) {
              reconnectAttemptsRef.current++;
              setErrorMessage(`Reconnecting... (${reconnectAttemptsRef.current}/${MAX_RECONNECT_ATTEMPTS})`);
              setTimeout(() => connect(true), 2500);
            } else {
              setErrorMessage("Connection failed.");
              setStatus(ConnectionStatus.ERROR);
              stopAllAudio();
            }
          },
          onclose: () => {
            if (status !== ConnectionStatus.ERROR && status !== ConnectionStatus.CONNECTING) {
              if (reconnectAttemptsRef.current < MAX_RECONNECT_ATTEMPTS && reconnectAttemptsRef.current > 0) {
                reconnectAttemptsRef.current++;
                connect(true);
              } else {
                setStatus(ConnectionStatus.DISCONNECTED);
                stopAllAudio();
                if (currentSessionMessages.length > 0) setShowSummary(true);
              }
            }
          },
        },
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error('Connection failed:', err);
      setStatus(ConnectionStatus.ERROR);
      stopAllAudio();
    }
  };

  const disconnect = () => {
    reconnectAttemptsRef.current = -1; 
    if (sessionRef.current) try { sessionRef.current.close(); } catch (e) {}
    stopAllAudio();
    setStatus(ConnectionStatus.DISCONNECTED);
    if (currentSessionMessages.length > 0) setShowSummary(true);
  };

  const handleExport = () => {
    if (!userProfile) return;
    const code = btoa(JSON.stringify(userProfile));
    setSyncCode(code);
    navigator.clipboard.writeText(code);
    alert('Memory code copied to clipboard! Send this to your other device.');
  };

  const handleImport = () => {
    try {
      const decoded = JSON.parse(atob(syncCode));
      if (decoded.name) {
        setUserProfile(decoded);
        localStorage.setItem('social_gemini_profile', JSON.stringify(decoded));
        setSyncCode('');
        alert('Memory synced successfully!');
      }
    } catch (e) {
      alert('Invalid sync code.');
    }
  };

  return (
    <div className="flex flex-col h-screen bg-black text-slate-100 p-4 md:p-10 font-sans overflow-hidden">
      <header className="flex justify-between items-center z-10 shrink-0">
        <div>
          <h1 className="text-xl font-black tracking-tighter bg-gradient-to-r from-orange-400 to-orange-600 bg-clip-text text-transparent">Social Gemini</h1>
          <div className="flex items-center space-x-2 mt-1">
            <span className={`w-2 h-2 rounded-full ${status === ConnectionStatus.CONNECTED ? 'bg-orange-500 animate-pulse' : 'bg-slate-800'}`}></span>
            <span className="text-[10px] uppercase font-bold text-slate-500 tracking-widest">{status}</span>
            {isWeakSignal && <span className="text-[9px] font-black text-orange-500 animate-pulse px-1.5 py-0.5 rounded border border-orange-500/20 ml-2">LOW SIGNAL</span>}
          </div>
        </div>
        <div className="flex space-x-2">
          <button onClick={() => setIsProfileModalOpen(true)} className="w-10 h-10 rounded-xl bg-slate-900 border border-white/5 flex items-center justify-center text-slate-400 hover:text-orange-500 transition-colors">
            <i className="fas fa-user-circle"></i>
          </button>
          <button onClick={() => setIsHistoryOpen(true)} className="w-10 h-10 rounded-xl bg-slate-900 border border-white/5 flex items-center justify-center text-orange-500 hover:bg-orange-500/10 transition-colors">
            <i className="fas fa-history"></i>
          </button>
        </div>
      </header>

      <main className="flex-1 flex flex-col items-center justify-center space-y-12 relative">
        <div className={`absolute w-64 h-64 bg-orange-500/5 rounded-full blur-3xl transition-opacity duration-1000 ${status === ConnectionStatus.CONNECTED ? 'opacity-100' : 'opacity-0'}`}></div>

        <button 
          onClick={status === ConnectionStatus.CONNECTED ? disconnect : () => connect()}
          className={`group relative w-48 h-48 rounded-[3.5rem] flex flex-col items-center justify-center border transition-all duration-700 orange-glow ${status === ConnectionStatus.CONNECTED ? 'border-orange-500/40 bg-orange-950/10 rotate-3 scale-105' : 'border-white/5 bg-slate-950 hover:border-orange-500/30'}`}
        >
          {status === ConnectionStatus.CONNECTED ? (
            <div className="flex flex-col items-center space-y-2">
               <i className="fas fa-broadcast-tower text-6xl text-orange-500 pulse-animation"></i>
            </div>
          ) : (
            <i className="fas fa-microphone text-slate-800 text-5xl group-hover:text-orange-500 transition-colors"></i>
          )}
        </button>

        <div className="w-full max-w-sm text-center space-y-6">
          <div className="h-16 flex items-center justify-center">
            <Waveform isActive={status === ConnectionStatus.CONNECTED} color="#f97316" amplitude={Math.max(rmsInput, rmsOutput)} />
          </div>
          <p className="text-slate-400 text-sm italic px-8 min-h-[48px] leading-relaxed">
            {transcription || (status === ConnectionStatus.CONNECTED ? "Listening..." : "Tap to start conversation.")}
          </p>
        </div>
      </main>

      <footer className="flex flex-col items-center pb-12 shrink-0">
        <button 
          onClick={status === ConnectionStatus.CONNECTED ? disconnect : () => connect()}
          className={`group flex items-center space-x-3 px-20 py-6 rounded-[2.5rem] font-black text-xs tracking-widest uppercase shadow-2xl transition-all active:scale-95 ${status === ConnectionStatus.CONNECTED ? 'bg-red-500/10 text-red-500 border border-red-500/20' : 'bg-gradient-to-br from-orange-500 to-orange-700 text-black shadow-orange-900/40'}`}
        >
          <i className={status === ConnectionStatus.CONNECTED ? 'fas fa-phone-slash' : 'fas fa-phone'}></i>
          <span>{status === ConnectionStatus.CONNECTED ? 'Hang Up' : 'Start Call'}</span>
        </button>
      </footer>

      {/* Profile Modal */}
      {isProfileModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-black/95 backdrop-blur-xl">
          <div className="w-full max-w-md bg-slate-900/50 border border-white/5 rounded-[3rem] p-10 space-y-6 max-h-[90vh] overflow-y-auto scrollbar-hide">
            <form onSubmit={(e) => {
              e.preventDefault();
              const fd = new FormData(e.currentTarget);
              const p = { 
                name: fd.get('name') as string, 
                relationship: '', 
                interests: (fd.get('interests') as string).split(','),
                petNames: fd.get('petNames') as string,
                dailyRoutine: fd.get('dailyRoutine') as string
              };
              setUserProfile(p);
              localStorage.setItem('social_gemini_profile', JSON.stringify(p));
              setIsProfileModalOpen(false);
            }} className="space-y-6">
              <div className="text-center">
                <h2 className="text-2xl font-black tracking-tight">Your Profile</h2>
                <p className="text-orange-500/60 text-[10px] uppercase font-bold tracking-widest mt-1">AI Context Memory</p>
              </div>
              <div className="space-y-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Name</label>
                  <input required name="name" defaultValue={userProfile?.name} className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-3 text-sm focus:border-orange-500/50 outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Interests (comma separated)</label>
                  <input name="interests" defaultValue={userProfile?.interests.join(',')} className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-3 text-sm focus:border-orange-500/50 outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Pet Names</label>
                  <textarea name="petNames" defaultValue={userProfile?.petNames} rows={2} className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-3 text-sm focus:border-orange-500/50 outline-none" placeholder="e.g. Buster the dog, Mittens the cat" />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Daily Routine</label>
                  <textarea name="dailyRoutine" defaultValue={userProfile?.dailyRoutine} rows={3} className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-3 text-sm focus:border-orange-500/50 outline-none" placeholder="e.g. Work 9-5, gym in the morning, reads before bed" />
                </div>
              </div>
              <button type="submit" className="w-full bg-orange-500 text-black font-black py-4 rounded-[2rem] hover:bg-orange-400 transition-colors uppercase text-xs tracking-widest">Update Memory</button>
            </form>

            <div className="pt-6 border-t border-white/5 space-y-4">
               <div className="text-center">
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">Manual Memory Sync</p>
                  <p className="text-[9px] text-slate-600 mt-1">Sync your profile with another device</p>
               </div>
               <div className="flex flex-col space-y-2">
                  <button onClick={handleExport} className="w-full bg-white/5 hover:bg-white/10 text-slate-300 py-3 rounded-xl text-[10px] font-bold uppercase tracking-widest border border-white/5 transition-all">
                     <i className="fas fa-copy mr-2"></i>Copy Memory Code
                  </button>
                  <div className="flex space-x-2">
                    <input 
                      value={syncCode} 
                      onChange={(e) => setSyncCode(e.target.value)}
                      placeholder="Paste code from desktop..." 
                      className="flex-1 bg-black border border-white/5 rounded-xl px-4 py-2 text-[10px] outline-none focus:border-orange-500/30"
                    />
                    <button onClick={handleImport} className="bg-orange-500/20 text-orange-500 px-4 py-2 rounded-xl text-[10px] font-bold uppercase tracking-widest hover:bg-orange-500/30 transition-all">
                      Sync
                    </button>
                  </div>
               </div>
            </div>

            <button type="button" onClick={() => setIsProfileModalOpen(false)} className="w-full text-slate-500 font-bold text-[10px] uppercase tracking-widest py-2">Close</button>
          </div>
        </div>
      )}

      {/* Summary Modal */}
      {showSummary && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/90 backdrop-blur-lg">
           <div className="w-full max-w-xl bg-slate-900/80 border border-white/10 rounded-[3rem] p-8 md:p-12 flex flex-col max-h-[85vh]">
              <div className="flex justify-between items-start mb-6">
                 <div>
                    <h2 className="text-2xl font-black tracking-tight">Call Summary</h2>
                    <p className="text-orange-500 text-[10px] font-black uppercase tracking-widest mt-1">Full Session Transcript</p>
                 </div>
                 <button onClick={() => setShowSummary(false)} className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center text-slate-400 hover:text-white transition-colors">
                    <i className="fas fa-times"></i>
                 </button>
              </div>
              <div className="flex-1 overflow-y-auto space-y-6 pr-2 scrollbar-hide">
                 {currentSessionMessages.map((msg, i) => (
                    <div key={i} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                       <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest mb-1 px-2">
                          {msg.role === 'user' ? userProfile?.name || 'You' : 'Zephyr'}
                       </span>
                       <div className={`max-w-[90%] px-5 py-3 rounded-[1.5rem] text-sm leading-relaxed ${msg.role === 'user' ? 'bg-orange-500 text-black rounded-tr-none' : 'bg-slate-800 text-slate-200 rounded-tl-none'}`}>
                          {msg.text}
                       </div>
                    </div>
                 ))}
              </div>
              <button onClick={() => setShowSummary(false)} className="mt-8 w-full bg-orange-500 text-black font-black py-4 rounded-2xl uppercase text-[10px] tracking-widest shadow-xl">
                 Close Transcript
              </button>
           </div>
        </div>
      )}

      {/* History Drawer */}
      {isHistoryOpen && (
        <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/80 backdrop-blur-sm">
          <div className="w-full max-w-2xl h-[80vh] bg-[#0a0a0a] border-t border-white/10 rounded-t-[4rem] p-8 md:p-12 flex flex-col">
            <div className="flex justify-between items-center mb-10">
              <h2 className="text-2xl font-black tracking-tighter">Call History</h2>
              <button onClick={() => setIsHistoryOpen(false)} className="w-12 h-12 rounded-2xl bg-slate-900 border border-white/5 flex items-center justify-center text-slate-400 hover:text-white transition-colors">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <div className="flex-1 overflow-y-auto space-y-8 pb-10 pr-2 scrollbar-hide">
              {history.map((msg, i) => (
                <div key={i} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                  <div className={`max-w-[85%] px-6 py-4 rounded-[2rem] text-sm leading-relaxed ${msg.role === 'user' ? 'bg-orange-500/90 text-black font-medium' : 'bg-slate-900 text-slate-200 border border-white/5'}`}>
                    {msg.text}
                  </div>
                  <span className="text-[8px] font-bold text-slate-600 mt-2 px-3 uppercase tracking-widest">{new Date(msg.timestamp).toLocaleString()}</span>
                </div>
              ))}
              {history.length === 0 && <p className="text-center text-slate-600 italic">No history yet.</p>}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { decode, decodeAudioData, createPcmBlob } from './audioUtils';
import { UserProfile, ChatMessage, ConnectionStatus } from './types';
import Waveform from './components/Waveform';

const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;
const MAX_RECONNECT_ATTEMPTS = 3;

const App: React.FC = () => {
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [isWeakSignal, setIsWeakSignal] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(() => {
    const saved = localStorage.getItem('social_gemini_profile');
    return saved ? JSON.parse(saved) : null;
  });

  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [showSummary, setShowSummary] = useState(false);
  const [currentSessionMessages, setCurrentSessionMessages] = useState<ChatMessage[]>([]);
  const [history, setHistory] = useState<ChatMessage[]>(() => {
    const saved = localStorage.getItem('social_gemini_history');
    return saved ? JSON.parse(saved) : [];
  });
  const [transcription, setTranscription] = useState<string>('');
  const [rmsInput, setRmsInput] = useState(0);
  const [rmsOutput, setRmsOutput] = useState(0);

  // Use refs for values needed in real-time callbacks to avoid stale closures
  const userInputBufferRef = useRef('');
  const modelOutputBufferRef = useRef('');
  const reconnectAttemptsRef = useRef(0);
  const lastSignalTimeRef = useRef(Date.now());
  const isMutedRef = useRef(false);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Instance refs
  const sessionRef = useRef<any>(null);
  const inputAudioCtxRef = useRef<AudioContext | null>(null);
  const outputAudioCtxRef = useRef<AudioContext | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);

  useEffect(() => {
    localStorage.setItem('social_gemini_history', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    isMutedRef.current = isMuted;
  }, [isMuted]);

  useEffect(() => {
    if (!userProfile) setIsProfileModalOpen(true);

    const interval = setInterval(() => {
      if (status === ConnectionStatus.CONNECTED && Date.now() - lastSignalTimeRef.current > 10000) {
        setIsWeakSignal(true);
      } else {
        setIsWeakSignal(false);
      }
    }, 5000);
    return () => clearInterval(interval);
  }, [userProfile, status]);

  const stopAllAudio = useCallback(() => {
    // 1. Stop all active playback sources
    sourcesRef.current.forEach(source => {
      try { source.stop(); } catch (e) {}
    });
    sourcesRef.current.clear();
    nextStartTimeRef.current = 0;
    setRmsOutput(0);
    setRmsInput(0);

    // 2. Disconnect microphone processor
    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current = null;
    }

    // 3. Stop media tracks
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }

    sessionRef.current = null;
  }, []);

  const connect = async (isReconnecting = false) => {
    if (status === ConnectionStatus.CONNECTING && !isReconnecting) return;

    try {
      setErrorMessage(null);
      setStatus(isReconnecting ? ConnectionStatus.RECONNECTING : ConnectionStatus.CONNECTING);
      setShowSummary(false);

      // Initialize Audio Contexts ONLY on user interaction
      if (!inputAudioCtxRef.current || inputAudioCtxRef.current.state === 'closed') {
        inputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: INPUT_SAMPLE_RATE });
      }
      if (!outputAudioCtxRef.current || outputAudioCtxRef.current.state === 'closed') {
        outputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: OUTPUT_SAMPLE_RATE });
      }

      const input = inputAudioCtxRef.current;
      const output = outputAudioCtxRef.current;

      // Resume context if suspended (common browser policy)
      if (input.state === 'suspended') await input.resume();
      if (output.state === 'suspended') await output.resume();

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const memoryContext = `
        User Name: ${userProfile?.name || 'Friend'}.
        Interests: ${userProfile?.interests.join(', ') || 'None'}.
        Pets: ${userProfile?.petNames || 'Not mentioned yet'}.
        Daily Routine: ${userProfile?.dailyRoutine || 'Not mentioned yet'}.
      `;

      const systemInstruction = `
        You are Zephyr, a warm and empathetic AI companion. You have a social, friendly personality.
        You are chatting with ${userProfile?.name || 'the user'}. 
        Important Persistent Context: ${memoryContext}
        Behavior: Be concise, supportive, and mention details from the context to show you care.
      `;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
          },
          systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setStatus(ConnectionStatus.CONNECTED);
            reconnectAttemptsRef.current = 0;
            lastSignalTimeRef.current = Date.now();

            const source = input.createMediaStreamSource(stream);
            const processor = input.createScriptProcessor(4096, 1, 1);
            processorRef.current = processor;

            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);

              if (isMutedRef.current) {
                setRmsInput(0);
                return;
              }

              // Visual feedback RMS
              let sum = 0;
              for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
              setRmsInput(Math.sqrt(sum / inputData.length));

              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then(session => {
                if (session) session.sendRealtimeInput({ media: pcmBlob });
              }).catch(err => console.error("Mic stream error:", err));
            };

            source.connect(processor);
            processor.connect(input.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            lastSignalTimeRef.current = Date.now();

            // Handle Audio
            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio) {
              try {
                const audioBuffer = await decodeAudioData(decode(base64Audio), output, OUTPUT_SAMPLE_RATE, 1);
                const source = output.createBufferSource();
                source.buffer = audioBuffer;

                // Track RMS for waveform
                setRmsOutput(0.8);

                source.connect(output.destination);
                nextStartTimeRef.current = Math.max(nextStartTimeRef.current, output.currentTime);
                source.start(nextStartTimeRef.current);
                nextStartTimeRef.current += audioBuffer.duration;

                sourcesRef.current.add(source);
                source.onended = () => {
                  sourcesRef.current.delete(source);
                  if (sourcesRef.current.size === 0) setRmsOutput(0);
                };
              } catch (e) {
                console.error("Audio processing failed", e);
              }
            }

            // Handle Transcriptions
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              userInputBufferRef.current += text;
              setTranscription(prev => (prev + ' ' + text).trim());
            }
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              modelOutputBufferRef.current += text;
              setTranscription(prev => (prev + ' ' + text).trim());
            }

            // Turn Finalization
            if (message.serverContent?.turnComplete) {
              const userTxt = userInputBufferRef.current.trim();
              const modelTxt = modelOutputBufferRef.current.trim();
              if (userTxt || modelTxt) {
                const msgs: ChatMessage[] = [
                  { role: 'user', text: userTxt || '(User spoke)', timestamp: Date.now() },
                  { role: 'model', text: modelTxt || '(Zephyr spoke)', timestamp: Date.now() }
                ];
                setHistory(prev => [...prev, ...msgs].slice(-50));
                setCurrentSessionMessages(prev => [...prev, ...msgs]);
              }
              userInputBufferRef.current = '';
              modelOutputBufferRef.current = '';
              setTimeout(() => setTranscription(''), 2000);
            }

            // Interrupt Handling
            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setRmsOutput(0);
            }
          },
          onerror: (e: any) => {
            const errorStr = e?.message || e?.toString() || '';
            console.error('Gemini Session Error:', errorStr);

            if (errorStr.includes('404') || errorStr.includes('not found')) {
              setErrorMessage("AI Studio key or project issue. Please check billing.");
              setStatus(ConnectionStatus.ERROR);
              stopAllAudio();
            } else if (reconnectAttemptsRef.current < MAX_RECONNECT_ATTEMPTS) {
              reconnectAttemptsRef.current++;
              setStatus(ConnectionStatus.RECONNECTING);
              setTimeout(() => connect(true), 3000);
            } else {
              setErrorMessage("Connection failed. Please check your signal.");
              setStatus(ConnectionStatus.ERROR);
              stopAllAudio();
            }
          },
          onclose: (e) => {
            console.log("Session closed", e);
            if (status !== ConnectionStatus.ERROR) {
              setStatus(ConnectionStatus.DISCONNECTED);
              stopAllAudio();
              if (currentSessionMessages.length > 0) setShowSummary(true);
            }
          },
        },
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error('Connection bootstrap failed:', err);
      setStatus(ConnectionStatus.ERROR);
      setErrorMessage("Could not start call. Access your microphone and try again.");
      stopAllAudio();
    }
  };

  const disconnect = () => {
    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch (e) {}
    }
    stopAllAudio();
    setStatus(ConnectionStatus.DISCONNECTED);
    if (currentSessionMessages.length > 0) setShowSummary(true);
  };

  const downloadTranscript = () => {
    const text = currentSessionMessages
      .map(m => `${m.role === 'user' ? (userProfile?.name || 'User') : 'Zephyr'}: ${m.text}`)
      .join('\n\n');
    const blob = new Blob([text], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `zephyr-chat-${new Date().toISOString().split('T')[0]}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="flex flex-col h-screen bg-black text-slate-100 p-6 md:p-12 font-sans overflow-hidden">
      {/* Dynamic Background Glow */}
      <div className={`fixed inset-0 pointer-events-none transition-opacity duration-[2000ms] ${status === ConnectionStatus.CONNECTED ? 'opacity-20' : 'opacity-0'}`}
           style={{ background: 'radial-gradient(circle at center, #f97316 0%, transparent 70%)' }}></div>

      <header className="flex justify-between items-center z-10">
        <div>
          <h1 className="text-2xl font-black tracking-tighter text-orange-500">Zephyr</h1>
          <div className="flex items-center space-x-2 mt-1">
            <div className={`w-2 h-2 rounded-full ${status === ConnectionStatus.CONNECTED ? 'bg-green-500 animate-pulse' : 'bg-slate-700'}`}></div>
            <span className="text-[10px] uppercase font-bold text-slate-500 tracking-widest">{status}</span>
          </div>
        </div>
        <div className="flex space-x-3">
          <button onClick={() => setIsHistoryOpen(true)} className="w-12 h-12 rounded-2xl bg-slate-900 border border-white/5 flex items-center justify-center text-slate-400 hover:text-orange-500 transition-all">
            <i className="fas fa-history"></i>
          </button>
          <button onClick={() => setIsProfileModalOpen(true)} className="w-12 h-12 rounded-2xl bg-slate-900 border border-white/5 flex items-center justify-center text-slate-400 hover:text-orange-500 transition-all">
            <i className="fas fa-user-circle"></i>
          </button>
        </div>
      </header>

      <main className="flex-1 flex flex-col items-center justify-center space-y-16 relative z-10">
        <div className="text-center space-y-2">
          {isWeakSignal && <p className="text-orange-500 text-[10px] font-black uppercase tracking-widest animate-pulse">Weak Signal Detected</p>}
          <h2 className="text-4xl md:text-6xl font-black tracking-tight leading-none">
            {status === ConnectionStatus.CONNECTED ? (isMuted ? 'Muted' : 'Speaking...') : 'Ready to talk?'}
          </h2>
        </div>

        <div className="relative group">
          <button 
            onClick={status === ConnectionStatus.CONNECTED ? disconnect : () => connect()}
            className={`relative w-56 h-56 rounded-[4rem] flex flex-col items-center justify-center border transition-all duration-1000 shadow-2xl ${status === ConnectionStatus.CONNECTED ? 'border-orange-500/50 bg-orange-950/20 scale-105' : 'border-white/10 bg-slate-900 hover:border-orange-500/30'}`}
          >
            {status === ConnectionStatus.CONNECTED ? (
              <i className="fas fa-wave-square text-6xl text-orange-500 animate-pulse"></i>
            ) : (
              <i className="fas fa-phone text-4xl text-slate-600 group-hover:text-orange-500 transition-colors"></i>
            )}
          </button>

          {status === ConnectionStatus.CONNECTED && (
            <button 
              onClick={() => setIsMuted(!isMuted)}
              className={`absolute -right-4 -bottom-4 w-16 h-16 rounded-3xl border transition-all shadow-2xl flex items-center justify-center ${isMuted ? 'bg-red-500 border-red-400 text-white' : 'bg-slate-800 border-white/10 text-orange-500'}`}
            >
              <i className={`fas ${isMuted ? 'fa-microphone-slash' : 'fa-microphone'} text-xl`}></i>
            </button>
          )}
        </div>

        <div className="w-full max-w-md text-center space-y-8">
          <Waveform isActive={status === ConnectionStatus.CONNECTED} color={isMuted ? "#64748b" : "#f97316"} amplitude={Math.max(rmsInput, rmsOutput)} />
          <p className="text-slate-400 text-lg md:text-xl font-medium px-4 min-h-[60px] italic line-clamp-2">
            {transcription || (errorMessage || "Tap the button to start a relaxed conversation with Zephyr.")}
          </p>
        </div>
      </main>

      <footer className="shrink-0 flex justify-center pb-10 z-10">
        <button 
          onClick={status === ConnectionStatus.CONNECTED ? disconnect : () => connect()}
          className={`px-12 py-5 rounded-full font-black text-xs uppercase tracking-[0.2em] transition-all shadow-2xl ${status === ConnectionStatus.CONNECTED ? 'bg-white/5 border border-white/10 text-red-500 hover:bg-red-500/10' : 'bg-orange-500 text-black hover:bg-orange-400'}`}
        >
          {status === ConnectionStatus.CONNECTED ? 'End Session' : 'Call Zephyr'}
        </button>
      </footer>

      {/* Profile Modal */}
      {isProfileModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-black/90 backdrop-blur-xl">
          <div className="w-full max-w-md bg-slate-900 border border-white/10 rounded-[3rem] p-10 space-y-8 shadow-2xl">
            <div className="text-center space-y-2">
              <h3 className="text-2xl font-black">Who are you?</h3>
              <p className="text-slate-500 text-sm italic">Zephyr remembers your stories across sessions.</p>
            </div>
            <form onSubmit={(e) => {
              e.preventDefault();
              const fd = new FormData(e.currentTarget);
              const p: UserProfile = {
                name: fd.get('name') as string,
                relationship: 'Friend',
                interests: (fd.get('interests') as string).split(',').map(i => i.trim()),
                petNames: fd.get('pets') as string,
                dailyRoutine: fd.get('routine') as string
              };
              setUserProfile(p);
              localStorage.setItem('social_gemini_profile', JSON.stringify(p));
              setIsProfileModalOpen(false);
            }} className="space-y-5">
              <input required name="name" placeholder="Name" defaultValue={userProfile?.name} className="w-full bg-black/50 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-orange-500/50" />
              <input name="interests" placeholder="Interests (Music, Gaming, Hiking)" defaultValue={userProfile?.interests.join(', ')} className="w-full bg-black/50 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-orange-500/50" />
              <input name="pets" placeholder="Pet Names" defaultValue={userProfile?.petNames} className="w-full bg-black/50 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-orange-500/50" />
              <textarea name="routine" placeholder="Briefly describe your daily routine..." defaultValue={userProfile?.dailyRoutine} className="w-full bg-black/50 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-orange-500/50 h-24 resize-none" />
              <button type="submit" className="w-full bg-orange-500 text-black font-black py-5 rounded-3xl hover:bg-orange-400 transition-all uppercase text-xs tracking-widest">Save Identity</button>
            </form>
          </div>
        </div>
      )}

      {/* Summary Modal */}
      {showSummary && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl">
          <div className="w-full max-w-md bg-slate-900/80 border border-white/5 rounded-[4rem] p-12 space-y-10 text-center animate-in zoom-in duration-500">
             <div className="space-y-4">
                <div className="w-20 h-20 bg-orange-500/10 text-orange-500 rounded-full flex items-center justify-center mx-auto">
                   <i className="fas fa-check-circle text-3xl"></i>
                </div>
                <h2 className="text-3xl font-black">Great Session!</h2>
                <p className="text-slate-400 italic">"I've updated my memories. Can't wait for our next talk."</p>
             </div>
             <div className="space-y-4">
                <button onClick={downloadTranscript} className="w-full flex items-center justify-center space-x-3 bg-white/5 border border-white/10 text-white py-5 rounded-3xl hover:bg-white/10 transition-all">
                   <i className="fas fa-file-download text-orange-500"></i>
                   <span className="text-xs font-black uppercase tracking-widest">Save Transcript</span>
                </button>
                <button onClick={() => setShowSummary(false)} className="w-full bg-orange-500 text-black font-black py-5 rounded-[2rem] hover:bg-orange-400 transition-all uppercase text-xs tracking-widest">
                   Goodbye for now
                </button>
             </div>
          </div>
        </div>
      )}

      {/* History Slide-over (Simple implementation) */}
      {isHistoryOpen && (
        <div className="fixed inset-0 z-50 flex justify-end bg-black/60 backdrop-blur-sm">
          <div className="w-full max-w-sm bg-slate-900 h-full p-8 space-y-6 overflow-y-auto">
            <div className="flex justify-between items-center">
              <h3 className="text-xl font-black">Recent Memory</h3>
              <button onClick={() => setIsHistoryOpen(false)} className="text-slate-500"><i className="fas fa-times"></i></button>
            </div>
            <div className="space-y-6">
              {history.length === 0 ? (
                <p className="text-slate-600 italic text-center py-20">No memories yet.</p>
              ) : (
                history.map((m, i) => (
                  <div key={i} className={`p-4 rounded-2xl ${m.role === 'user' ? 'bg-slate-800/50' : 'bg-orange-500/5 border border-orange-500/10'}`}>
                    <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">{m.role === 'user' ? 'You' : 'Zephyr'}</p>
                    <p className="text-sm leading-relaxed">{m.text}</p>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { decode, decodeAudioData, createPcmBlob } from './audioUtils';
import { UserProfile, ConnectionStatus } from './types';
import Waveform from './components/Waveform';

const INPUT_SAMPLE_RATE = 16000;
const OUTPUT_SAMPLE_RATE = 24000;

const App: React.FC = () => {
  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [isMuted, setIsMuted] = useState(false);
  const [isInitialized, setIsInitialized] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('social_gemini_profile');
    return saved ? JSON.parse(saved) : { name: 'Friend', interests: [], relationship: 'Companion' };
  });

  const [transcription, setTranscription] = useState<string>('');
  const [rmsInput, setRmsInput] = useState(0);
  const [rmsOutput, setRmsOutput] = useState(0);

  const sessionRef = useRef<any>(null);
  const inputAudioCtxRef = useRef<AudioContext | null>(null);
  const outputAudioCtxRef = useRef<AudioContext | null>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const nextStartTimeRef = useRef<number>(0);
  const isMutedRef = useRef(false);

  useEffect(() => { isMutedRef.current = isMuted; }, [isMuted]);

  const stopEverything = useCallback(() => {
    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();
    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
      sessionRef.current = null;
    }
    setStatus(ConnectionStatus.DISCONNECTED);
  }, []);

  const initializeZephyr = async () => {
    try {
      setErrorMessage(null);
      setStatus(ConnectionStatus.CONNECTING);

      // 1. API Key Pre-flight
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        if (!hasKey) {
          await window.aistudio.openSelectKey();
          // Proceed immediately after calling openSelectKey to handle the race condition
        }
      }

      // 2. Warm up Audio Contexts (Atomic step within user gesture)
      if (!inputAudioCtxRef.current) {
        inputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: INPUT_SAMPLE_RATE });
      }
      if (!outputAudioCtxRef.current) {
        outputAudioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: OUTPUT_SAMPLE_RATE });
      }

      await inputAudioCtxRef.current.resume();
      await outputAudioCtxRef.current.resume();

      // 3. Requesting Signal (Mic)
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      // 4. Establishing Link
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
          },
          systemInstruction: `You are Zephyr. You are a witty, relaxed conversationalist. 
          You are chatting with ${userProfile.name}. Interests: ${userProfile.interests.join(', ')}.
          Be warm, concise, and sound like a person. Mention user details naturally but sparingly.
          Humor is encouraged, especially dry wit. If there's a silence, wait patiently.`,
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setStatus(ConnectionStatus.CONNECTED);
            setIsInitialized(true);

            const source = inputAudioCtxRef.current!.createMediaStreamSource(stream);
            const processor = inputAudioCtxRef.current!.createScriptProcessor(4096, 1, 1);

            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              if (isMutedRef.current) { setRmsInput(0); return; }

              let sum = 0;
              for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
              setRmsInput(Math.sqrt(sum / inputData.length));

              const pcmBlob = createPcmBlob(inputData);
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };

            source.connect(processor);
            processor.connect(inputAudioCtxRef.current!.destination);
          },
          onmessage: async (msg: LiveServerMessage) => {
            const base64 = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64) {
              const buffer = await decodeAudioData(decode(base64), outputAudioCtxRef.current!, OUTPUT_SAMPLE_RATE, 1);
              const source = outputAudioCtxRef.current!.createBufferSource();
              source.buffer = buffer;
              source.connect(outputAudioCtxRef.current!.destination);

              setRmsOutput(0.9);

              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputAudioCtxRef.current!.currentTime);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;

              sourcesRef.current.add(source);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setRmsOutput(0);
              };
            }

            const text = msg.serverContent?.modelTurn?.parts?.[0]?.text || 
                         msg.serverContent?.outputTranscription?.text;
            if (text) setTranscription(text);

            if (msg.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => {
            console.error("Signal Lost:", e);
            setErrorMessage("The link was severed. Check your connection or API key.");
            if (e.toString().includes('404')) {
              window.aistudio?.openSelectKey();
            }
            stopEverything();
          },
          onclose: () => {
            setStatus(ConnectionStatus.DISCONNECTED);
            stopEverything();
          }
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error("Boot Failure:", err);
      setStatus(ConnectionStatus.ERROR);
      setErrorMessage("System failed to initialize. Microphone or subspace interference.");
    }
  };

  if (!isInitialized) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-black-gradient p-6">
        <div className="w-full max-w-xl bg-slate-900/50 border border-white/10 rounded-[2.5rem] p-12 space-y-10 orange-glow">
          <div className="text-center space-y-4">
            <div className="flex justify-center">
              <div className="w-20 h-20 bg-orange-500/10 rounded-full flex items-center justify-center border border-orange-500/20 pulse-animation">
                <i className="fa-solid fa-satellite-dish text-3xl text-orange-500"></i>
              </div>
            </div>
            <h1 className="text-4xl font-light tracking-tight text-white">Zephyr Link</h1>
            <p className="text-slate-400 text-lg">Establishing a direct neural-audio connection.</p>
          </div>

          <form onSubmit={(e) => { e.preventDefault(); initializeZephyr(); }} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-xs font-medium text-slate-500 uppercase tracking-widest px-2">Operator Name</label>
                <input 
                  type="text" 
                  value={userProfile.name}
                  onChange={(e) => setUserProfile({...userProfile, name: e.target.value})}
                  className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-4 text-white focus:outline-none focus:border-orange-500/50 transition-colors"
                />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-medium text-slate-500 uppercase tracking-widest px-2">Designation</label>
                <input 
                  type="text" 
                  value={userProfile.relationship}
                  onChange={(e) => setUserProfile({...userProfile, relationship: e.target.value})}
                  className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-4 text-white focus:outline-none focus:border-orange-500/50 transition-colors"
                />
              </div>
            </div>

            {errorMessage && (
              <div className="bg-red-500/10 border border-red-500/20 text-red-400 px-4 py-3 rounded-xl text-sm flex items-center gap-3">
                <i className="fa-solid fa-circle-exclamation"></i>
                {errorMessage}
              </div>
            )}

            <button 
              type="submit"
              disabled={status === ConnectionStatus.CONNECTING}
              className="w-full py-5 bg-orange-500 hover:bg-orange-600 disabled:opacity-50 disabled:cursor-not-allowed text-black font-bold text-xl rounded-3xl transition-all active:scale-[0.98] shadow-lg shadow-orange-500/20"
            >
              {status === ConnectionStatus.CONNECTING ? 'Calibrating...' : 'Initiate Link'}
            </button>

            <p className="text-center text-xs text-slate-600 uppercase tracking-widest">
              Gemini Native Audio Engine v2.5-Flash
            </p>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen bg-black overflow-hidden">
      {/* Header */}
      <header className="flex items-center justify-between px-8 py-6 border-b border-white/5 bg-black/50 backdrop-blur-xl z-10">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-orange-500/10 rounded-full flex items-center justify-center border border-orange-500/20">
            <i className="fa-solid fa-wind text-orange-500"></i>
          </div>
          <div>
            <h2 className="text-lg font-medium text-white tracking-wide">Zephyr</h2>
            <div className="flex items-center gap-2">
              <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></div>
              <span className="text-[10px] uppercase tracking-[0.2em] text-slate-500 font-semibold">Neural Link Active</span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={() => setIsMuted(!isMuted)}
            className={`w-12 h-12 rounded-full flex items-center justify-center transition-all ${isMuted ? 'bg-red-500/20 text-red-500 border-red-500/30' : 'bg-white/5 text-slate-400 border-white/10'} border`}
          >
            <i className={`fa-solid ${isMuted ? 'fa-microphone-slash' : 'fa-microphone'}`}></i>
          </button>
          <button 
            onClick={stopEverything}
            className="w-12 h-12 bg-white/5 border border-white/10 rounded-full flex items-center justify-center text-slate-400 hover:text-white transition-colors"
          >
            <i className="fa-solid fa-power-off"></i>
          </button>
        </div>
      </header>

      {/* Main Conversation Visualizer */}
      <main className="flex-1 flex flex-col items-center justify-center p-8 relative">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(249,115,22,0.05)_0%,transparent_70%)]"></div>

        <div className="w-full max-w-2xl flex flex-col items-center gap-12 z-10">
          <div className="space-y-4 w-full text-center">
            <p className="text-slate-500 text-xs uppercase tracking-[0.3em] font-medium">Subspace Waveform</p>
            <div className="w-full bg-slate-900/40 border border-white/5 rounded-[2rem] p-10 flex flex-col gap-6">
              <Waveform isActive={status === ConnectionStatus.CONNECTED} color="#f97316" amplitude={rmsOutput || rmsInput} />
            </div>
          </div>

          <div className="w-full text-center min-h-[100px] flex flex-col justify-center gap-4">
            <p className="text-slate-600 text-[10px] uppercase tracking-widest font-bold">Transcription Stream</p>
            <p className="text-2xl text-slate-300 font-light leading-relaxed italic">
              {transcription || "Listening for your voice..."}
            </p>
          </div>
        </div>
      </main>

      {/* Footer Info */}
      <footer className="px-8 py-4 border-t border-white/5 bg-black/50 text-center">
        <p className="text-[10px] text-slate-700 uppercase tracking-[0.4em]">
          Connected to {userProfile.name} • Protocol Level 4 • No Vogon Filing Required
        </p>
      </footer>
    </div>
  );
};

export default App;
